INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2026-12-30', E'길르앗 야베스 사건과 사무엘의 고별사 (사무엘상 12장)', E'사무엘상 12장', E'사무엘의 고별 연설은 이스라엘 역사의 중요한 전환점을 보여줍니다. 지도자로서의 공적 사역을 마무리하며, 사무엘은 먼저 자신의 청렴했던 삶을 백성 앞에 내놓습니다. "내가 누구의 소를 빼앗았느냐 누구의 나귀를 빼앗았느냐"(삼상 12:3)라는 그의 물음에 백성은 한목소리로 그의 정직함을 증언합니다. 이는 단순한 자기변호가 아니라, 하나님의 종으로서 걸어온 길에 대한 확증이었습니다.\n\n이어서 사무엘은 이스라엘의 역사를 되짚으며 하나님의 신실하심을 상기시킵니다. 애굽에서의 구원, 가나안 정착, 그리고 사사들을 통한 구원의 역사가 펼쳐집니다. 그러나 동시에 백성의 반복된 배신도 지적합니다. 하나님을 잊고 바알과 아스다롯을 섬겼던 과거, 그리고 이제는 하나님이 왕이심에도 불구하고 인간 왕을 요구한 현재의 모습까지 낱낱이 드러냅니다.\n\n놀라운 것은 이런 불신앙에도 불구하고 하나님의 약속은 변함이 없다는 사실입니다. 사무엘은 밀 베는 때가 아님에도 우레와 비를 내리시는 기적을 통해 하나님의 주권을 확증합니다. 두려워하는 백성에게 사무엘이 전하는 메시지는 명확합니다. 비록 왕을 구한 것이 잘못이었지만, 이제라도 마음을 다해 여호와를 섬기면 된다는 것입니다. "여호와께서는 그의 크신 이름을 위해서라도 자기 백성을 버리지 아니하실 것"이라는 약속은 하나님의 변함없는 은혜를 보여줍니다.\n\n사무엘은 자신도 기도를 쉬는 것이 죄가 될 것임을 고백하며, 끝까지 백성을 위해 기도하고 가르치겠다고 다짐합니다. 왕정 시대가 시작되었지만, 진정한 왕은 여전히 여호와이심을 잊지 말라는 것이 그의 마지막 당부였습니다.', E'오늘의 핵심\n사무엘은 왕정 시대를 맞이한 이스라엘에게 하나님의 신실하심을 상기시키며, 비록 왕을 세웠지만 여전히 여호와만을 섬겨야 함을 강조합니다.\n\n묵상 질문\n1. 사무엘처럼 청렴하고 정직한 삶의 증거가 내게도 있나요?\n2. 실패와 잘못에도 불구하고 나를 버리지 않으시는 하나님의 은혜를 경험한 적이 있나요?\n3. 내가 쉬지 말고 해야 할 기도의 제목은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2026-12-31', E'사울의 블레셋 전투 (사무엘상 13장)', E'사무엘상 13장', E'블레셋의 대군이 해변의 모래처럼 몰려오자 이스라엘 백성은 굴과 바위틈에 숨고, 요단 건너편으로 도망치기까지 합니다. 병거 삼만, 마병 육천, 그리고 셀 수 없는 보병의 위세 앞에서 이스라엘은 완전히 위축되었습니다. 사울 곁에 남은 백성마저 하나둘 흩어지고, 겨우 육백 명만이 떨며 그를 따르고 있었습니다.\n\n사무엘이 정한 이레의 기한이 거의 다 되었지만 그는 오지 않았고, 사울의 마음은 조급함으로 가득 찼습니다. 백성은 흩어지고, 적군은 코앞까지 진을 쳤으며, 사무엘은 약속한 시간에 나타나지 않았습니다. 결국 사울은 제사장이 아닌 자신이 직접 번제를 드리기로 결정합니다. 그리고 번제를 마치자마자, 마치 기다렸다는 듯이 사무엘이 도착합니다.\n\n사울의 변명은 그럴듯해 보입니다. "백성은 내게서 흩어지고 당신은 정한 날 안에 오지 아니하고 블레셋 사람은 믹마스에 모였음을 내가 보았으므로"(삼상 13:11). 전쟁을 앞두고 여호와께 은혜를 구하지 못할까 봐 부득이하게 번제를 드렸다는 것입니다. 그러나 사무엘은 이를 ''망령된 행위''라고 단호히 선언합니다.\n\n사울의 근본적인 문제는 상황의 급박함이 아니었습니다. 그의 마음에 하나님을 온전히 신뢰하고 기다리는 자리가 없었다는 것이 문제였습니다. 사울에게 번제는 하나님 앞에 자신을 내려놓는 예배가 아니라, 백성의 민심을 수습하고 전쟁의 승리를 보장받기 위한 수단에 불과했습니다. 그는 보이는 상황에 압도되어 보이지 않는 하나님의 때를 기다리지 못했습니다.\n\n이 사건으로 인해 사울은 왕위를 잃게 됩니다. 하나님께서는 "그의 마음에 맞는 사람"을 이미 준비하고 계셨습니다. 작은 불순종처럼 보이지만, 이는 사울의 마음 중심이 하나님이 아닌 자신과 상황에 있음을 드러낸 결정적인 사건이었습니다. 하나님께서는 능력이 아닌 마음을 보시며, 성과가 아닌 순종을 기뻐하십니다. 오늘도 우리는 ''부득이하다''는 핑계로 하나님의 방법 대신 내 방식을 선택하려는 유혹을 받습니다. 그러나 진정한 믿음은 보이는 현실이 아닌 보이지 않는 하나님의 약속을 붙잡고 끝까지 기다리는 것입니다.', E'오늘의 핵심\n사울은 급박한 상황을 핑계로 하나님의 명령을 어기고 스스로 번제를 드렸으며, 이는 그의 마음이 하나님께 온전히 향하지 않았음을 보여주는 결정적인 사건이 되었습니다.\n\n묵상 질문\n1. 내가 ''부득이하다''며 하나님의 뜻보다 내 판단을 앞세웠던 때는 언제인가요?\n2. 상황이 급박할 때 하나님을 끝까지 기다린다는 것은 무엇을 의미할까요?\n3. 오늘 내 삶에서 하나님의 때를 기다려야 할 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-01', E'사울의 블레셋 전투 (사무엘상 14장)', E'사무엘상 14장', E'하루는 요나단이 무기 든 소년과 단둘이 블레셋 진영으로 향합니다. 사울이 육백 명의 병사와 함께 석류나무 아래 머물러 있는 동안, 그의 아들은 믿음의 모험을 시작한 것입니다. 험한 바위 사이를 지나며 요나단이 한 고백은 놀랍습니다. "여호와의 구원은 사람이 많고 적음에 달리지 아니하였느니라." 이는 단순한 용기가 아니라 하나님의 능력을 온전히 신뢰하는 믿음의 고백이었습니다.\n\n요나단은 하나님께서 주실 표징을 구하며 나아갑니다. 블레셋 사람들이 "우리에게로 올라오라"고 말하면 그것을 하나님께서 그들을 넘기신 증거로 받아들이겠다는 것이었습니다. 그리고 정확히 그 일이 일어납니다. 요나단과 그의 무기 든 자가 처음 쳐죽인 자가 이십 명 가량이었고, 이어서 하나님께서 블레셋 진영에 큰 떨림을 일으키셨습니다. 땅까지 진동하는 이 혼란은 하나님께서 직접 개입하신 초자연적인 역사였습니다.\n\n그런데 승리의 날에 사울은 또다시 잘못된 결정을 내립니다. "저녁까지 아무 음식물이든지 먹는 사람은 저주를 받을지어다"라는 성급한 맹세를 한 것입니다. 이로 인해 백성들은 극도로 피곤해졌고, 결국 피째로 고기를 먹는 죄를 범하게 됩니다. 요나단이 꿀을 먹고 눈이 밝아진 것과 대조적으로, 사울의 경솔한 맹세는 오히려 백성을 죄에 빠뜨리고 승리를 제한하는 결과를 낳았습니다.\n\n같은 전쟁터에서 아버지와 아들은 전혀 다른 모습을 보여줍니다. 요나단은 하나님을 신뢰하며 담대히 나아갔고, 사울은 인간적인 열심으로 잘못된 명령을 내렸습니다. 요나단의 믿음은 하나님의 큰 역사를 이끌어냈지만, 사울의 맹세는 백성을 곤경에 빠뜨렸습니다. 하나님께서는 한 사람의 온전한 믿음을 통해서도 능히 구원을 이루실 수 있음을 이 본문은 생생히 보여주고 있습니다.', E'오늘의 핵심\n요나단의 믿음 있는 행동은 하나님의 놀라운 승리로 이어졌지만, 사울의 성급한 맹세는 오히려 백성을 죄에 빠뜨리는 걸림돌이 되었습니다.\n\n묵상 질문\n1. 요나단처럼 "여호와의 구원은 사람의 많고 적음에 달리지 않았다"고 고백할 수 있는 믿음이 내게 있나요?\n2. 나의 열심이 오히려 하나님의 일을 방해하거나 다른 사람에게 무거운 짐이 된 적은 없었나요?\n3. 오늘 내가 직면한 상황에서 하나님의 능력을 온전히 신뢰하며 나아갈 일은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-02', E'사울의 불순종과 다윗의 기름 부음 (사무엘상 15장)', E'사무엘상 15장', E'사울이 왕이 된 지 20여 년, 이스라엘은 주변 민족들과의 전쟁에서 승리를 거듭하며 강성해졌습니다. 이때 하나님께서는 사울에게 특별한 사명을 주십니다. 아말렉을 완전히 진멸하라는 것이었습니다. 아말렉은 이스라엘이 출애굽할 때 대열에서 뒤처진 약자들을 공격했던 민족입니다. 수백 년이 지났지만 그들은 여전히 약한 자들을 괴롭히는 삶을 이어가고 있었고, 공의의 하나님께서는 그들의 악행에 대한 심판을 명하셨습니다.\n\n사울은 20만의 군대를 이끌고 아말렉을 공격해 승리를 거둡니다. 그러나 하나님의 명령을 온전히 수행하지는 않았습니다. 왕 아각을 사로잡고, 좋은 가축들을 남겨두었던 것입니다. 돌아온 사울은 사무엘에게 "내가 여호와의 명령을 행하였나이다"라고 보고하지만, 사무엘의 귀에는 양과 소의 울음소리가 들려왔습니다. \n\n사울의 변명은 계속됩니다. 백성들이 하나님께 제사하려고 좋은 것들을 남겼다고 말합니다. 그러나 사무엘은 그 유명한 말씀을 선포합니다. "순종이 제사보다 낫고 듣는 것이 숫양의 기름보다 나으니"(삼상 15:22). 하나님께서 원하시는 것은 화려한 제사가 아니라 그분의 말씀에 대한 온전한 순종이었습니다.\n\n사울은 자신의 잘못을 인정하면서도 그 이유를 백성에 대한 두려움 때문이라고 고백합니다. 하나님보다 사람을 더 두려워했던 것입니다. 더욱이 그는 이스라엘을 "내 백성"이라고 부르며, 하나님의 백성을 자신의 소유로 여기는 교만함까지 드러냅니다. 결국 사무엘은 하나님께서 사울을 왕위에서 폐하셨다는 엄중한 선고를 전합니다. 거역은 점치는 죄와 같고, 완고함은 우상숭배와 같다는 말씀과 함께 말입니다.\n\n라마로 돌아간 사무엘은 죽는 날까지 사울을 다시 보지 않았습니다. 한 시대를 이끌어야 할 지도자가 하나님의 말씀에 불순종함으로써 버림받은 것에 대한 깊은 슬픔이 그의 마음을 무겁게 했습니다.', E'오늘의 핵심\n하나님께서는 형식적인 종교 행위보다 말씀에 대한 온전한 순종을 원하시며, 사람을 두려워하여 하나님의 명령을 어긴 사울을 왕위에서 폐하셨습니다.\n\n묵상 질문\n1. 내가 하나님께 드리는 예배와 헌신 속에 진정한 순종이 있나요, 아니면 형식적인 종교 행위에 머물러 있나요?\n2. 하나님의 뜻을 알면서도 사람들의 시선이나 평가 때문에 순종하지 못한 경험이 있다면 무엇인가요?\n3. 오늘 하나님께서 내게 요구하시는 ''완전한 순종''의 영역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-04', E'사울의 불순종과 다윗의 기름 부음 (사무엘상 16장)', E'사무엘상 16장', E'사울이 하나님의 말씀에 불순종한 결과는 참으로 엄중했습니다. 하나님께서는 사무엘을 통해 사울을 버리셨다는 선언을 하셨고, 이제 새로운 왕을 준비하십니다. 사무엘이 사울을 위해 슬퍼하고 있을 때, 하나님께서는 "언제까지 슬퍼하겠느냐"고 물으시며 베들레헴으로 가서 이새의 아들 중 한 명에게 기름을 부으라고 명하십니다. 사무엘이 사울의 보복을 두려워하자, 하나님께서는 제사를 핑계로 가라는 지혜로운 방법을 알려주십니다.\n\n베들레헴에 도착한 사무엘 앞에 이새의 아들들이 차례로 나타납니다. 첫째 엘리압을 본 사무엘은 그의 훌륭한 외모에 감탄하며 이 사람이 하나님의 기름부음 받을 자라고 확신했습니다. 그러나 하나님께서는 "그의 용모와 키를 보지 말라 내가 이미 그를 버렸노라 내가 보는 것은 사람과 같지 아니하니 사람은 외모를 보거니와 나 여호와는 중심을 보느니라"(삼상 16:7)고 말씀하십니다. 이 말씀은 하나님의 선택 기준이 인간의 기준과 얼마나 다른지를 보여줍니다.\n\n일곱 아들이 모두 지나갔지만 아무도 택함받지 못했습니다. 사무엘이 다른 아들이 있는지 묻자, 이새는 막내가 양을 치고 있다고 대답합니다. 양을 치던 막내 다윗이 불려왔을 때, 하나님께서는 바로 그가 택한 자임을 알려주셨고, 사무엘은 그에게 기름을 부었습니다. 그 순간부터 다윗은 여호와의 영에 크게 감동되었습니다.\n\n반면 사울에게서는 여호와의 영이 떠나고 악령이 그를 괴롭히기 시작했습니다. 신하들의 제안으로 수금을 잘 타는 자를 찾던 중, 바로 그 다윗이 사울의 궁으로 부름받게 됩니다. 다윗이 수금을 탈 때마다 사울을 괴롭히던 악령이 떠나갔습니다. 이렇게 하나님께서는 버림받은 왕과 새로 택함받은 왕을 한 자리에 모으시며, 새로운 시대를 준비하십니다. 하나님의 섭리는 참으로 오묘하여, 다윗은 자신이 대체할 왕을 섬기는 것으로 왕의 길을 시작하게 됩니다.', E'오늘의 핵심\n하나님께서는 외모가 아닌 중심을 보시며 다윗을 택하셨고, 여호와의 영이 사울에게서 떠나 다윗에게 임하면서 이스라엘의 새로운 시대가 열립니다.\n\n묵상 질문\n1. 하나님께서 사람의 중심을 보신다는 말씀이 내게는 위로가 되나요, 아니면 부담이 되나요?\n2. 내가 사람을 평가할 때 외모나 조건을 먼저 보고 있지는 않은가요?\n3. 다윗처럼 낮은 자리에서도 충실히 섬길 준비가 되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-05', E'다윗의 골리앗 전투 승리와 요나단과의 우정 (사무엘상 17장)', E'사무엘상 17장', E'엘라 골짜기에서 이스라엘과 블레셋의 군대가 40일째 대치하고 있었습니다. 블레셋의 장수 골리앗은 여섯 규빗 한 뼘(약 3m)의 거대한 키에 놋 투구와 5천 세겔(약 57kg)의 갑옷으로 무장한 채 매일 이스라엘을 조롱하며 도전했습니다. "너희는 한 사람을 택하여 내게로 내려보내라"(삼상 17:8)는 골리앗의 외침에 사울과 온 이스라엘은 크게 두려워했습니다.\n\n바로 이때 아버지 이새의 심부름으로 형들에게 음식을 전하러 온 목동 다윗이 이 광경을 목격합니다. 다윗의 눈에 비친 것은 단순히 거대한 적장이 아니라 "살아 계시는 하나님의 군대를 모욕하는" 할례받지 않은 블레셋 사람이었습니다. 큰형 엘리압은 다윗의 담대함을 교만으로 오해하며 꾸짖었지만, 다윗은 흔들리지 않았습니다.\n\n사울 앞에 선 다윗은 자신의 목동 경험을 들어 확신을 전합니다. 양을 지키며 사자와 곰을 물리쳤던 것처럼, 여호와께서 이번에도 자신을 건져주실 것이라는 믿음이었습니다. 왕의 군복과 갑옷 대신 평소 익숙한 물매와 시냇가의 매끄러운 돌 다섯 개를 택한 다윗의 모습은 하나님께서 일하시는 방식을 보여줍니다. 세상의 힘과 무기가 아닌, 여호와를 향한 신뢰가 진정한 무기임을 다윗은 알고 있었던 것입니다.\n\n베들레헴의 무명 목동이었던 다윗을 통해 하나님께서는 당신의 이름과 백성을 지키시는 분이심을 드러내십니다. 두려움에 사로잡힌 이스라엘 군대와 대조되는 다윗의 담대함은 하나님의 살아계심을 믿는 믿음에서 나온 것이었습니다.', E'오늘의 핵심\n하나님께서는 거대한 골리앗 앞에서 두려워하는 이스라엘을 위해 믿음의 목동 다윗을 준비시키셨습니다. 다윗의 담대함은 살아계신 하나님을 향한 신뢰에서 나왔습니다.\n\n묵상 질문\n1. 내 삶의 골리앗은 무엇이며, 그것이 나를 두렵게 만드는 이유는 무엇인가요?\n2. 다윗처럼 일상의 작은 경험 속에서 하나님의 신실하심을 발견한 적이 있나요?\n3. 세상의 방법이 아닌 하나님의 방법으로 문제를 해결하려면 어떤 믿음이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-06', E'다윗의 골리앗 전투 승리와 요나단과의 우정 (사무엘상 18장)', E'사무엘상 18장', E'골리앗과의 싸움에서 승리한 다윗이 사울 앞에 서게 되었을 때, 놀라운 일이 일어납니다. 왕세자 요나단의 마음이 다윗의 마음과 하나가 되어 그를 자기 생명 같이 사랑하게 된 것입니다. 요나단은 다윗과 언약을 맺고 자신의 겉옷과 군복, 그리고 칼과 활과 띠까지 벗어 주었습니다. 왕위 계승자가 자신의 왕권을 상징하는 물품들을 다윗에게 넘겨준 이 행위는 단순한 우정을 넘어서는 깊은 의미를 담고 있습니다.\n\n사울은 다윗을 자기 곁에 머물게 하고 군대의 장으로 삼았습니다. 다윗은 사울이 보내는 곳마다 가서 지혜롭게 행동했고, 온 백성과 사울의 신하들도 그를 합당하게 여겼습니다. 그런데 블레셋과의 전쟁에서 돌아올 때 여인들이 "사울이 죽인 자는 천천이요 다윗은 만만이로다"라고 노래하자, 사울의 마음에 시기와 두려움이 일어나기 시작합니다.\n\n그날 이후 사울은 다윗을 주목하며 경계했고, 악령이 그를 사로잡을 때마다 다윗을 해치려 했습니다. 사울은 다윗을 제거하려는 계략을 꾸며 딸들을 미끼로 사용하기까지 했습니다. 처음에는 맏딸 메랍을 주겠다고 했다가 다른 사람에게 주었고, 다윗을 사랑하는 둘째 딸 미갈을 주면서도 블레셋 사람들의 포피 백 개를 요구하여 그가 전쟁에서 죽기를 바랐습니다.\n\n그러나 하나님께서 다윗과 함께하셨기에 그는 모든 위험을 극복하고 오히려 이백 명의 블레셋 사람을 죽여 왕의 요구를 두 배로 채웠습니다. 사울은 여호와께서 다윗과 함께 계심을 알고 더욱 두려워했고, 평생 다윗의 대적이 되어버렸습니다. 한 사람의 시기심이 어떻게 영혼을 파괴하고 관계를 망가뜨리는지를 보여주는 안타까운 장면입니다.', E'오늘의 핵심\n하나님이 함께하시는 다윗을 요나단은 생명처럼 사랑했지만, 사울은 시기와 두려움으로 대적했습니다. 같은 사람을 보면서도 전혀 다른 반응을 보이는 두 사람의 모습이 우리에게 많은 것을 생각하게 합니다.\n\n묵상 질문\n1. 하나님이 쓰시는 사람을 볼 때 나는 요나단처럼 기뻐하나요, 아니면 사울처럼 시기하나요?\n2. 시기심이 내 마음을 사로잡을 때 어떻게 그것을 극복할 수 있을까요?\n3. 하나님이 함께하시는 삶의 증거가 내게도 나타나고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-07', E'다윗의 골리앗 전투 승리와 요나단과의 우정 (사무엘상 19장)', E'사무엘상 19장', E'사울의 질투가 살의로 변하면서 다윗의 생명이 위태로워집니다. 하나님께서 다윗과 함께하시는 것을 누구보다 잘 알던 사울이었지만, 왕권에 대한 집착이 그의 판단력을 흐리게 만들었습니다. 이때 요나단의 우정이 빛을 발합니다. 아버지의 명령보다 하나님의 뜻과 의로움을 더 중요하게 여긴 요나단은 다윗의 생명을 구하기 위해 적극적으로 나섭니다. \n\n요나단의 중재로 잠시 화해가 이루어지는 듯했지만, 다윗이 또다시 블레셋과의 전쟁에서 큰 승리를 거두자 사울의 시기심은 다시 타오릅니다. 악령에 사로잡힌 사울이 단창을 던져 다윗을 죽이려 하는 장면은 한때 다윗의 수금 소리로 평안을 얻었던 왕의 변화된 모습을 극명하게 보여줍니다. \n\n위기의 순간, 하나님께서는 미갈을 통해 다윗을 보호하십니다. 사울의 딸이면서 다윗의 아내인 미갈이 남편을 창문으로 내려보내고 꾀를 써서 추격을 늦춘 것은 하나님의 섭리였습니다. 다윗이 사무엘에게로 피신한 후에 일어난 일은 더욱 놀랍습니다. 다윗을 잡으러 온 사울의 전령들이 오히려 하나님의 영에 사로잡혀 예언을 하고, 급기야 사울 자신까지도 하나님의 영 앞에 무력해집니다. \n\n벗은 몸으로 하루 밤낮을 누워 있는 사울의 모습은 하나님 앞에서 인간의 권력이 얼마나 무력한지를 보여주는 동시에, 하나님께서 당신의 택하신 자를 보호하시는 방법이 얼마나 주권적인지를 드러냅니다. 하나님께서는 요나단의 우정, 미갈의 기지, 그리고 성령의 직접적인 개입을 통해 다윗을 지키셨습니다.', E'오늘의 핵심\n하나님께서는 사울의 집요한 추격 속에서도 여러 사람과 초자연적인 방법을 통해 다윗을 보호하시며, 당신의 계획은 인간의 악의로도 막을 수 없음을 보여주십니다.\n\n묵상 질문\n1. 위기의 순간에 하나님께서 예상치 못한 사람이나 방법으로 나를 도우신 경험이 있나요?\n2. 요나단처럼 옳은 일을 위해 권위에 맞서야 할 때, 나는 어떤 선택을 하고 있나요?\n3. 하나님의 영 앞에서 무력해진 사울을 보며, 내가 놓아야 할 집착은 무엇인지 생각해봅시다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-08', E'기도로 여는 하늘문 (사무엘상 20장)', E'사무엘상 20장', E'사울의 살의가 걷잡을 수 없이 커지면서 다윗은 극도의 위기에 몰립니다. 라마 나욧에서 도망쳐 나온 다윗이 요나단을 찾아와 절박하게 묻습니다. "나와 죽음의 사이는 한 걸음뿐이니라"(삼상 20:3). 이 처절한 고백에는 억울함과 두려움이 가득합니다. 자신이 무엇을 잘못했기에 왕이 자신의 생명을 노리는지 알 수 없었던 다윗의 마음이 얼마나 답답했을까요.\n\n요나단은 친구의 생명을 지키기 위해 아버지의 마음을 살피기로 합니다. 초하루 왕의 식탁에서 다윗의 빈자리를 두고 사울의 반응을 확인하는 것이었습니다. 둘째 날 사울이 다윗의 부재를 묻자, 요나단은 다윗이 베들레헴의 가족 제사에 참석했다고 둘러댑니다. 그 순간 사울의 분노가 폭발합니다. 심지어 아들 요나단에게 단창을 던져 죽이려 할 정도였습니다.\n\n이 장면은 질투와 두려움이 한 사람을 얼마나 파괴적으로 만드는지 보여줍니다. 사울은 다윗이 자신의 왕위를 위협한다고 생각했습니다. 그러나 요나단의 반응은 달랐습니다. 그는 왕위 계승자임에도 불구하고 다윗이 하나님께 선택받은 사람임을 인정했습니다. "여호와께서 내 아버지와 함께 하신 것 같이 너와 함께 하시기를 원하노니"라는 요나단의 고백에는 하나님의 뜻에 순복하는 겸손한 믿음이 담겨 있습니다.\n\n에셀 바위에서의 마지막 만남은 두 친구의 우정이 얼마나 깊었는지를 보여줍니다. 화살을 신호로 삼아 위험을 알리는 요나단의 지혜로운 계획, 그리고 서로를 위해 눈물을 흘리며 작별하는 모습에서 우리는 진정한 우정의 아름다움을 봅니다. 요나단은 자신의 왕위 계승권보다 하나님의 뜻과 친구와의 언약을 더 소중히 여겼습니다. 이것이 바로 믿음의 사람이 보여주는 진정한 위대함입니다.', E'오늘의 핵심\n요나단은 왕위 계승권을 포기하면서까지 하나님의 뜻을 인정하고, 생명의 위협 속에서도 다윗과의 언약을 지켜 진정한 믿음의 우정을 보여줍니다.\n\n묵상 질문\n1. 나는 하나님의 뜻이 내 계획과 다를 때 요나단처럼 순복할 수 있을까요?\n2. 질투와 두려움이 내 마음을 지배하지 않도록 어떻게 경계하고 있나요?\n3. 하나님 앞에서 맺은 약속과 관계를 신실하게 지키고 있는지 돌아봅시다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-09', E'기도로 여는 하늘문 (사무엘상 21장)', E'사무엘상 21장', E'사울의 위협을 피해 도망친 다윗이 제사장들의 성읍 놉에 도착합니다. 떨리는 마음으로 다윗을 맞이한 아히멜렉 제사장은 왕의 사위이자 군대 장관인 다윗이 홀로 온 것을 의아해합니다. 다윗은 왕의 비밀 임무 수행 중이라고 둘러대며 먹을 것과 무기를 요청합니다. 긴박한 도피 상황에서 진실을 말할 수 없었던 다윗의 곤경이 드러나는 장면입니다.\n\n아히멜렉은 보통 떡은 없고 오직 거룩한 진설병만 있다고 답합니다. 율법에 따르면 진설병은 제사장만 먹을 수 있었지만, 아히멜렉은 생명의 위기에 처한 다윗에게 이를 내어줍니다. 또한 골리앗의 칼까지 건네주며 다윗을 돕습니다. 하나님의 기름부음 받은 자를 향한 제사장의 긍휼이 율법의 형식을 넘어섰습니다. 그러나 이 장면을 사울의 목자장 도엑이 지켜보고 있었다는 불길한 복선이 깔립니다.\n\n놉을 떠난 다윗은 더욱 절박한 선택을 합니다. 이스라엘의 원수 블레셋 땅으로 도망간 것입니다. 그러나 가드 왕 아기스의 신하들이 "사울이 죽인 자는 천천이요 다윗은 만만이로다"라는 노래를 언급하며 다윗의 정체를 알아봅니다. 궁지에 몰린 다윗은 미친 사람인 척하며 대문짝에 낙서하고 침을 흘립니다. 이스라엘의 영웅이 적국에서 광인 행세를 해야 했던 처절한 순간입니다.\n\n하나님의 약속을 받았지만 현실은 도피와 굴욕의 연속이었습니다. 그러나 다윗은 바로 이 시기에 시편 34편을 지어 "여호와를 찾는 자는 모든 좋은 것에 부족함이 없으리로다"라고 고백합니다. 가장 낮은 자리에서도 하나님을 신뢰하는 믿음, 이것이 다윗을 하나님의 마음에 합한 자로 만들어가는 과정이었습니다.', E'오늘의 핵심\n극한의 위기 속에서 거짓말과 미친 척하기까지 해야 했던 다윗의 모습을 통해, 하나님의 약속이 성취되기까지의 과정이 얼마나 험난한지를 보여줍니다. 그러나 다윗은 가장 비참한 순간에도 하나님을 찬양하는 믿음을 잃지 않았습니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 약속과 현실 사이의 간극으로 인해 좌절했던 때는 언제였나요?\n2. 생존을 위해 체면과 자존심을 내려놓아야 했던 다윗처럼, 나도 겸손히 낮아져야 할 영역이 있을까요?\n3. 가장 어려운 상황에서도 하나님을 찬양할 수 있는 믿음을 어떻게 키워갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-11', E'임명권자 하나님 (사무엘상 23장)', E'사무엘상 23장', E'블레셋이 그일라를 침공했다는 소식이 다윗에게 전해집니다. 그일라는 유다 지파에게 분배된 성읍으로, 지금 막 추수한 곡식을 블레셋에게 약탈당하고 있었습니다. 사울에게 쫓기는 도망자 신세인 다윗에게는 이 일이 자신과 무관한 일일 수 있었습니다. 그러나 다윗은 여호와께 묻습니다. 하나님께서는 "가서 블레셋 사람들을 치고 그일라를 구원하라"(삼상 23:2)고 명하십니다. \n\n다윗의 부하들은 두려워합니다. 사울의 추격을 피해 숨어 지내는 것만도 벅찬데, 블레셋과 싸우는 것은 너무나 위험한 일이었기 때문입니다. 다윗은 다시 한 번 여호와께 묻고, 하나님의 확실한 응답을 받은 후에야 그일라로 향합니다. 이 과정은 다윗이 얼마나 철저하게 하나님의 뜻을 구하며 살았는지를 보여줍니다.\n\n그일라를 구원한 다윗이지만, 그곳 주민들은 사울이 군대를 이끌고 오자 다윗을 배신할 것이라는 하나님의 경고를 받습니다. 은혜를 원수로 갚는 인간의 연약함이 드러나는 순간입니다. 다윗은 실망하거나 원망하지 않고 조용히 그곳을 떠납니다. 이후 광야를 전전하며 사울의 추격을 피하던 다윗에게 요나단이 찾아옵니다. 요나단은 하나님의 약속을 상기시키며 다윗의 믿음을 굳게 세워줍니다. \n\n십 사람들까지 다윗의 행방을 밀고하는 상황에서, 다윗은 점점 더 궁지에 몰립니다. 마온 광야에서는 사울의 군대에 완전히 포위될 뻔했으나, 절체절명의 순간에 블레셋의 침공 소식이 전해져 사울이 철수합니다. 하나님께서는 다윗이 블레셋과 싸워 그일라를 구했던 그 블레셋을 통해 다윗을 구원하신 것입니다. 하나님의 섭리는 이처럼 신묘합니다.', E'오늘의 핵심\n도망자 신세임에도 하나님의 명령에 순종하여 그일라를 구원한 다윗은, 배신과 추격 속에서도 하나님의 특별한 보호하심을 경험합니다.\n\n묵상 질문\n1. 어려운 상황에서도 하나님의 뜻을 먼저 구하고 순종하는 삶을 살고 있나요?\n2. 선을 악으로 갚는 사람들을 만났을 때 어떻게 반응하시나요?\n3. 절망적인 순간에 하나님의 섭리를 경험한 적이 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-12', E'임명권자 하나님 (사무엘상 24장)', E'사무엘상 24장', E'엔게디 광야의 어느 굴에서 놀라운 일이 벌어집니다. 이스라엘 전체에서 선발된 삼천 명의 정예부대를 이끌고 다윗을 추격하던 사울이, 하필이면 다윗과 그의 사람들이 숨어있는 바로 그 굴로 들어온 것입니다. 운명의 장난처럼 보이는 이 순간, 다윗의 부하들은 흥분하여 속삭입니다. 하나님께서 원수를 다윗의 손에 넘기신다는 약속이 바로 지금 이루어지고 있다고 말입니다.\n\n그러나 다윗은 전혀 다른 선택을 합니다. 사울의 겉옷 자락만을 베어낸 후, 그마저도 마음에 찔림을 느낍니다. "내가 손을 들어 여호와의 기름 부음을 받은 내 주를 치는 것은 여호와께서 금하시는 것이니"(삼상 24:6)라는 그의 고백은, 자신의 안전보다 하나님의 주권을 더 중요하게 여기는 믿음의 결단을 보여줍니다. 왕위를 약속받았지만 그것을 자기 손으로 쟁취하지 않고 하나님의 때를 기다리는 다윗의 모습에서, 우리는 참된 믿음의 본질을 발견합니다.\n\n굴을 나와 사울을 부르는 다윗의 외침에는 억울함이 아닌 존경이 담겨 있습니다. 땅에 엎드려 절하며 "내 아버지여"라고 부르는 그의 모습은, 자신을 죽이려는 사울을 향한 깊은 연민과 사랑을 드러냅니다. 이 장면을 목격한 사울은 비로소 자신의 잘못을 깨닫고 눈물을 흘립니다. "너는 나보다 의롭도다"라는 사울의 고백은, 권력에 눈이 멀어 하나님의 뜻을 거스른 자신과 달리 끝까지 하나님의 방법을 선택한 다윗의 의로움을 인정하는 것이었습니다.\n\n다윗이 보여준 이러한 자비와 절제는 단순한 정치적 계산이나 도덕적 우월감에서 비롯된 것이 아닙니다. 그것은 하나님의 주권을 온전히 신뢰하는 믿음에서 나온 행동이었습니다. 복수할 수 있는 완벽한 기회를 포기하고 하나님께 심판을 맡기는 다윗의 모습은, 오늘 우리에게도 깊은 도전을 줍니다. 상처받고 억울한 상황에서도 하나님의 때와 방법을 기다릴 수 있는 믿음, 그것이 바로 다윗을 통해 하나님께서 우리에게 가르쳐 주시는 귀한 교훈입니다.', E'오늘의 핵심\n다윗은 사울을 죽일 수 있는 절호의 기회에도 불구하고 하나님의 기름 부음받은 자를 해치지 않음으로써, 하나님의 주권을 존중하고 그분의 때를 기다리는 참된 믿음의 본을 보여줍니다.\n\n묵상 질문\n1. 내 손에 복수할 기회가 주어질 때, 나는 하나님께 심판을 맡길 수 있을까요?\n2. 다윗처럼 원수를 "내 아버지"라고 부를 수 있는 사랑의 마음을 품고 있나요?\n3. 하나님의 약속을 기다리며 인내하는 것이 어려운 영역은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-13', E'하나님의 테스트 (사무엘상 25장)', E'사무엘상 25장', E'시대의 거목이었던 사무엘이 하나님의 부르심을 받아 영원한 안식에 들어갑니다. 온 이스라엘이 모여 애도하는 가운데, 다윗은 홀로 바란 광야로 내려가야 했습니다. 영적 멘토의 부재는 다윗에게 큰 상실감을 안겨주었을 것입니다. 바로 이때 하나님께서는 뜻밖의 사건을 통해 다윗의 삶에 개입하십니다.\n\n갈멜의 부자 나발은 다윗과 그의 부하들이 목자들을 보호해준 은혜를 모욕으로 갚았습니다. 분노한 다윗이 칼을 차고 나발의 집을 치러 갈 때, 하나님께서는 총명한 여인 아비가일을 보내어 피의 보복을 막으십니다. 아비가일의 지혜로운 말은 다윗의 마음을 돌이켰습니다. "내 주의 손으로 피를 흘려 친히 보복하시는 일을 여호와께서 막으셨으니"(삼상 25:26)라는 그녀의 고백은 다윗으로 하여금 하나님의 섭리를 깨닫게 합니다.\n\n아비가일은 단순히 위기를 모면하려는 것이 아니었습니다. 그녀는 다윗이 장차 이스라엘의 지도자가 될 것을 내다보며, 무죄한 피를 흘리는 일이 훗날 그의 양심에 걸림돌이 되지 않기를 간구했습니다. 이는 다윗이 사울을 두 번이나 살려준 일과 같은 맥락에서, 하나님께서 복수를 친히 행하시도록 맡기는 믿음의 원칙을 다시 한번 확인시켜 줍니다.\n\n열흘 후 나발이 하나님의 치심으로 죽자, 다윗은 아비가일을 아내로 맞이합니다. 하나님께서는 사무엘이 떠난 빈자리를 지혜로운 동반자로 채워주신 것입니다. 이 사건은 우리에게 중요한 교훈을 줍니다. 감정적 대응이 아닌 하나님의 때와 방법을 기다리는 믿음, 그리고 위기의 순간에 하나님께서 예비하신 도움의 손길을 신뢰하는 것입니다.', E'오늘의 핵심\n하나님께서는 분노에 사로잡힌 다윗을 지혜로운 아비가일을 통해 막으시고, 복수를 친히 갚으시며 다윗에게 새로운 동반자를 허락하십니다.\n\n묵상 질문\n1. 분노와 복수심이 솟구칠 때, 나는 하나님의 음성에 귀를 기울이고 있나요?\n2. 내 삶에 아비가일처럼 지혜로운 조언을 해주는 사람이 있나요?\n3. 하나님께 복수를 맡기고 기다리는 믿음을 실천하고 계신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-14', E'하나님의 테스트 (사무엘상 26장)', E'사무엘상 26장', E'십 사람들이 다시 사울에게 다윗의 위치를 밀고합니다. 삼천 명의 정예군을 이끌고 하길라 산으로 출동한 사울은 진영 가운데 누워 잠들어 있었고, 다윗과 아비새가 그곳에 잠입했을 때 여호와께서 그들을 깊이 잠들게 하셨습니다. 아비새는 절호의 기회라며 사울을 단번에 죽이자고 제안하지만, 다윗은 단호히 거절합니다. "누구든지 손을 들어 여호와의 기름 부음 받은 자를 치면 죄가 없겠느냐"(삼상 26:9)는 다윗의 고백은 그가 여전히 하나님의 주권을 온전히 인정하고 있음을 보여줍니다.\n\n엔게디 동굴 사건에 이어 두 번째로 주어진 이 기회는 하나님께서 다윗의 믿음을 시험하시는 것이었습니다. 다윗은 사울의 창과 물병만을 가지고 나와 멀리 산꼭대기에서 외칩니다. 잠에서 깨어난 사울은 자신의 생명이 다윗의 손에 달려 있었음을 깨닫고 다시 한 번 자신의 잘못을 인정합니다. 그러나 이전과 마찬가지로 이는 일시적 감정에 불과했습니다.\n\n다윗의 선택은 단순한 정치적 계산이 아니었습니다. 그는 하나님께서 사울을 심판하실 때와 방법을 정하실 것임을 믿었습니다. "여호와께서 그를 치시리니 혹은 죽을 날이 이르거나 또는 전장에 나가서 망하리라"는 다윗의 말은 하나님의 시간표를 전적으로 신뢰하는 믿음의 고백입니다. 복수할 권리를 포기하고 하나님께 맡기는 것, 이것이 하나님의 사람이 걷는 길입니다. 다윗은 자기 손으로 왕위를 쟁취하는 대신 하나님의 때를 기다리는 믿음의 길을 선택했습니다.', E'오늘의 핵심\n다윗은 사울을 죽일 수 있는 두 번째 기회에도 하나님의 주권을 인정하며, 복수를 포기하고 하나님의 때를 기다리는 믿음을 보여줍니다.\n\n묵상 질문\n1. 내게 복수할 기회가 주어질 때, 나는 다윗처럼 하나님께 맡길 수 있나요?\n2. 하나님의 시간표를 기다리기 어려운 상황에서도 믿음으로 인내하고 있나요?\n3. 여호와의 기름 부음 받은 자를 존중하는 것처럼, 나는 하나님의 권위를 인정하며 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-15', E'종이 된 다윗 왕 (사무엘하 1장)', E'사무엘하 1장', E'길보아 산의 비극적인 전투 소식이 시글락에 있던 다윗에게 전해집니다. 한 아말렉 청년이 사울의 진영에서 도망쳐 와 사울과 요나단의 죽음을 알리는데, 그는 자신이 사울을 죽였다고 주장하며 왕관과 팔찌를 증거물로 가져옵니다. 아마도 이 청년은 다윗이 사울과 적대 관계였음을 알고 상급을 기대했을 것입니다. 그러나 다윗의 반응은 전혀 예상 밖이었습니다.\n\n다윗은 옷을 찢으며 애통해했고, 함께 있던 모든 사람들과 더불어 저녁때까지 금식하며 울었습니다. 그리고 "네가 어찌하여 손을 들어 여호와의 기름 부음 받은 자 죽이기를 두려워하지 아니하였느냐"(삼하 1:14)고 물으며, 그 청년을 처형하게 합니다. 다윗에게 사울은 여전히 ''여호와의 기름 부음 받은 자''였습니다. 개인적인 핍박과 고난에도 불구하고, 하나님께서 세우신 권위를 존중하는 마음은 변하지 않았던 것입니다.\n\n이어지는 다윗의 애가는 그의 진심을 더욱 분명히 보여줍니다. "사울과 요나단이 생전에 사랑스럽고 아름다운 자이러니"라고 노래하며, 특별히 요나단에 대해서는 "그대가 나를 사랑함이 기이하여 여인의 사랑보다 더하였도다"라고 고백합니다. 원수의 죽음을 기뻐하기는커녕, 그들의 고귀함과 용맹을 기억하고 애도하는 다윗의 모습은 하나님의 마음을 닮은 사람의 품격을 보여줍니다.\n\n우리는 종종 우리를 힘들게 했던 사람들이 어려움을 당할 때 은밀한 기쁨을 느끼곤 합니다. 그러나 다윗은 자신을 죽이려 했던 사울의 죽음 앞에서도 진정한 애도를 표현했습니다. 이것이 바로 하나님께서 다윗을 ''내 마음에 합한 사람''이라 부르신 이유였을 것입니다.', E'오늘의 핵심\n다윗은 자신을 핍박했던 사울의 죽음 소식에 기뻐하지 않고 오히려 진심으로 애통해하며, 여호와의 기름 부음 받은 자에 대한 존경심을 끝까지 지킵니다.\n\n묵상 질문\n1. 나를 힘들게 했던 사람이 어려움을 당할 때, 나는 어떤 마음이 드나요?\n2. 다윗처럼 원수까지도 사랑하고 존중할 수 있는 마음은 어디에서 올까요?\n3. 오늘 내가 화해하고 용서해야 할 사람은 누구일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-16', E'종이 된 다윗 왕 (사무엘하 2장)', E'사무엘하 2장', E'사울이 죽은 후, 다윗은 곧바로 왕위에 오르지 않고 먼저 여호와께 물었습니다. "내가 유다 한 성읍으로 올라가리이까"(삼하 2:1). 오랜 도피 생활을 끝내고 마침내 왕이 될 때가 왔음에도, 다윗은 자신의 뜻대로 움직이지 않고 하나님의 인도하심을 구한 것입니다. 하나님께서는 헤브론으로 가라고 명하셨고, 그곳에서 유다 사람들이 다윗에게 기름을 부어 왕으로 삼았습니다.\n\n다윗이 왕이 되어 처음 한 일은 길르앗 야베스 사람들에게 감사를 표현하는 것이었습니다. 그들이 사울의 시체를 수습하여 장사한 일을 높이 평가하며 축복의 말을 전했습니다. 이는 다윗이 단순히 권력을 추구하는 사람이 아니라, 의로운 일을 행한 이들을 기억하고 격려하는 지도자임을 보여줍니다.\n\n그러나 이스라엘의 통합은 순탄하지 않았습니다. 사울의 군사령관 아브넬이 사울의 아들 이스보셋을 왕으로 세우면서 나라가 둘로 나뉘게 되었습니다. 유다는 다윗을, 나머지 이스라엘은 이스보셋을 따르는 분열의 시대가 시작된 것입니다. 기브온 못가에서 양측 군대가 대치했고, 처음에는 각 열두 명씩 나와 겨루는 것으로 시작했지만 곧 치열한 전투로 번졌습니다.\n\n이 싸움에서 가장 비극적인 일은 요압의 동생 아사헬의 죽음이었습니다. 젊고 빠른 아사헬은 아브넬을 끈질기게 추격했고, 아브넬의 거듭된 만류에도 물러서지 않다가 결국 창에 찔려 죽고 말았습니다. 형제가 형제를 죽이는 이 참혹한 광경은 분열된 이스라엘의 비극을 고스란히 보여줍니다.\n\n결국 아브넬이 "칼이 영원히 사람을 상하겠느냐"(삼하 2:26)고 외치자 요압이 나팔을 불어 전투를 중단시켰습니다. 양측 모두 깊은 상처를 안고 각자의 진영으로 돌아갔습니다. 이날의 싸움은 단순한 정치적 대립을 넘어, 같은 민족끼리 서로를 죽이는 비극적 내전의 서막이었습니다. 하나님의 뜻을 구하며 시작한 다윗의 왕권도 이러한 아픔의 과정을 거쳐야만 했습니다.', E'오늘의 핵심\n사울 사후 다윗이 유다의 왕이 되었으나, 사울의 아들 이스보셋이 북이스라엘의 왕이 되면서 동족상잔의 비극적 내전이 시작되었습니다.\n\n묵상 질문\n1. 다윗은 왕이 될 때가 왔음에도 왜 먼저 하나님께 물었을까요?\n2. 같은 민족이 서로 싸우는 모습을 보며 어떤 마음이 드나요?\n3. 내 삶에서 하나님의 인도하심을 구해야 할 중요한 결정은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-18', E'다윗의 세 번째 기름 부음과 통일왕조 수립 (사무엘하 3장)', E'사무엘하 3장', E'사울의 집과 다윗의 집 사이에 전쟁이 오래 지속되던 중, 마침내 전환점이 찾아옵니다. 사울의 군대장관이었던 아브넬이 이스보셋과의 갈등 끝에 다윗에게로 향합니다. 그는 단순히 개인적 배신이 아니라 이스라엘 장로들의 뜻을 모아 왔습니다. "너희가 여러 번 다윗을 너희의 임금으로 세우기를 구하였으니"(삼하 3:17)라는 아브넬의 말은 북이스라엘 백성들도 이미 다윗을 왕으로 인정하고 있었음을 보여줍니다.\n\n다윗은 아브넬과의 만남에서 지혜로운 모습을 보입니다. 먼저 미갈을 돌려받음으로써 사울 왕가와의 정당한 연결고리를 회복하고, 아브넬을 극진히 대접하며 평화롭게 보냅니다. 7년 반의 분열을 끝낼 통일의 문이 열리는 순간이었습니다. 그러나 요압의 개인적 복수심이 이 모든 것을 무너뜨립니다. 동생 아사헬의 원한을 갚는다며 평화의 사자 아브넬을 암살한 것입니다.\n\n이 위기의 순간, 다윗의 반응이 주목할 만합니다. 그는 정치적 계산이 아닌 진심 어린 애도로 응답합니다. 옷을 찢고, 굵은 베를 띠고, 아브넬의 무덤에서 소리 높여 울며, 해가 지도록 금식했습니다. 무엇보다 아브넬을 위한 애가를 지어 불렀는데, 그 내용은 아브넬이 명예롭게 죽지 못한 것에 대한 깊은 애통함이었습니다. "불의한 자식의 앞에 엎드러짐 같이 네가 엎드러졌도다"라는 표현에는 의로운 사람이 억울하게 죽은 것에 대한 다윗의 분노와 슬픔이 담겨 있습니다.\n\n다윗의 이런 진실한 애도는 백성들의 마음을 움직였습니다. "이 날에야 온 백성과 온 이스라엘이 넬의 아들 아브넬을 죽인 것이 왕이 한 것이 아닌 줄을 아니라"는 본문의 증언처럼, 백성들은 다윗의 진정성을 알아보았습니다. 하나님께서는 인간의 복수심이 만든 위기 상황에서도, 한 사람의 진실한 마음을 통해 더 큰 화합의 길을 여셨습니다. 우리도 억울한 오해나 위기를 만날 때, 성급한 자기변호보다 하나님 앞에서의 진실함으로 반응한다면, 그것이 오히려 사람들의 마음을 얻는 길이 될 수 있음을 배웁니다.', E'오늘의 핵심\n다윗은 요압의 복수로 인한 정치적 위기를 진실한 애도와 하나님 앞에서의 정직함으로 극복하며, 백성들의 신뢰를 얻습니다.\n\n묵상 질문\n1. 요압처럼 개인적 원한이 하나님의 큰 계획을 방해한 적이 내 삶에도 있나요?\n2. 다윗의 진심 어린 애도가 백성의 마음을 돌렸듯이, 나도 진정성으로 회복해야 할 관계가 있을까요?\n3. 억울한 오해를 받을 때 성급한 변명보다 하나님 앞에서의 진실함을 선택할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-19', E'다윗의 세 번째 기름 부음과 통일왕조 수립 (사무엘하 4장)', E'사무엘하 4장', E'아브넬의 죽음 소식이 북쪽 이스라엘에 전해지자 이스보셋의 손에는 힘이 빠지고 온 백성이 두려움에 사로잡힙니다. 권력의 실세가 사라진 왕국은 이제 누가 봐도 무너질 위기에 놓였습니다. 이때 이스보셋의 군지휘관 두 사람, 레갑과 바아나가 기회를 엿봅니다. 그들은 낮잠을 자던 이스보셋을 암살하고 그 머리를 베어 다윗에게 가져갑니다. "왕의 원수 사울의 아들 이스보셋의 머리가 여기 있나이다"라며 큰 공을 세운 듯 자랑스럽게 말합니다.\n\n그러나 다윗의 반응은 그들의 기대와 정반대였습니다. 다윗은 분명히 선을 긋습니다. 전에 사울의 죽음을 알린 자도 좋은 소식인 줄 알았지만 처형했는데, 하물며 의인을 자기 집 침상에서 죽인 악행을 어찌 용납할 수 있겠느냐고 말합니다. 결국 다윗은 그들을 처형하고 이스보셋의 머리는 정중히 아브넬의 무덤에 매장합니다.\n\n다윗의 이런 일관된 태도는 단순한 정치적 계산이 아닙니다. 그는 정적이라 할지라도 하나님의 형상대로 지음받은 한 생명의 존엄성을 귀히 여겼습니다. 권력을 위해서라면 어떤 수단도 정당화될 수 있다고 여기는 세상의 논리와 달리, 다윗은 하나님의 때와 방법을 끝까지 신뢰했습니다. 이런 원칙 있는 리더십이 결국 백성들의 마음을 얻게 됩니다.\n\n오늘날 우리도 목적을 위해 수단을 정당화하려는 유혹을 받습니다. 승진을 위해, 이익을 위해, 심지어 선한 목적을 위해서라도 작은 불의를 눈감아 줄 때가 있습니다. 그러나 하나님은 결과만큼이나 과정을 중요하게 보십니다. 다윗처럼 하나님의 때를 기다리며 정직한 길을 걷는 것, 그것이 진정한 승리의 길입니다.', E'오늘의 핵심\n다윗은 자신에게 유리한 이스보셋의 암살을 단호히 거부하고 암살자들을 처형함으로써, 생명의 존엄성과 하나님의 방법을 지키는 원칙 있는 리더십을 보여줍니다.\n\n묵상 질문\n1. 레갑과 바아나는 왜 다윗이 기뻐할 것이라고 착각했을까요?\n2. 목적이 선하다고 해서 수단을 정당화하려는 유혹이 내 삶에도 있지 않나요?\n3. 다윗처럼 하나님의 때와 방법을 신뢰하며 기다려야 할 일은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-20', E'다윗의 세 번째 기름 부음과 통일왕조 수립 (사무엘하 5장)', E'사무엘하 5장', E'이스라엘 모든 지파가 헤브론으로 모여 다윗에게 나아와 고백합니다. "보소서 우리는 왕의 한 골육이니이다"(삼하 5:1). 사울이 왕이었을 때에도 실제로 이스라엘을 이끌었던 사람이 다윗이었음을 이제야 인정하는 것입니다. 기름 부음 받은 지 약 20년, 유다의 왕이 된 지 7년 6개월 만에 마침내 하나님의 약속이 온전히 이루어집니다. 열한 지파의 장로들이 다윗과 언약을 맺고, 그에게 기름을 부어 통일 이스라엘의 왕으로 세웁니다.\n\n통일왕국의 첫 과제는 수도를 정하는 일이었습니다. 다윗은 유다와 베냐민 지파 경계에 위치한 예루살렘을 선택합니다. 여부스 족속이 "맹인과 다리 저는 자라도 너를 물리치리라"며 조롱할 정도로 난공불락의 요새였지만, 다윗은 지혜롭게 물 긷는 통로로 침투하여 성을 점령합니다. 이곳은 ''다윗 성''이 되어 통일왕국의 중심지가 됩니다.\n\n예루살렘에 자리 잡은 다윗에게 두로 왕 히람이 사절단과 건축 자재, 기술자들을 보내옵니다. 이방 왕의 인정은 다윗 왕국이 국제적 위상을 갖추게 되었음을 보여줍니다. 다윗은 이 모든 것이 하나님께서 이스라엘을 위하여 자신의 나라를 높이신 것임을 깨닫습니다.\n\n그러나 축복에는 도전이 따릅니다. 다윗이 이스라엘의 왕이 되었다는 소식을 들은 블레셋이 총공세를 펼칩니다. 다윗은 매번 여호와께 물어 전쟁에 임합니다. 첫 번째 전투에서는 정면 돌파로, 두 번째 전투에서는 우회 기습으로 승리합니다. 특히 뽕나무 꼭대기의 발걸음 소리를 신호로 삼으라는 하나님의 세밀한 인도하심이 인상적입니다. 다윗의 승리는 군사력이 아닌 하나님과의 교통에서 나온 것이었습니다.\n\n오랜 기다림 끝에 왕위에 오른 다윗은 자신의 높아짐이 이스라엘을 위한 하나님의 계획임을 잊지 않았습니다. 우리도 승진이나 성공의 자리에 올라갈 때, 그것이 나를 통해 이루실 하나님의 더 큰 뜻을 위함임을 기억해야 합니다.', E'오늘의 핵심\n다윗은 온 이스라엘의 왕이 되어 예루살렘을 수도로 삼고, 매 전투마다 하나님께 묻고 순종함으로 승리합니다.\n\n묵상 질문\n1. 오랜 기다림 끝에 받은 축복을 어떻게 하나님의 영광을 위해 사용할 수 있을까요?\n2. 다윗처럼 중요한 결정 앞에서 먼저 하나님께 묻고 있나요?\n3. 내가 높아진 자리에서도 하나님의 백성을 위한 마음을 유지하려면 어떻게 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-21', E'종이 된 다윗 왕 (사무엘하 6장)', E'사무엘하 6장', E'다윗이 왕위에 오른 후 가장 먼저 한 일 중 하나는 하나님의 궤를 예루살렘으로 모셔오는 것이었습니다. 블레셋에게 빼앗겼다가 돌아온 후 기럇여아림에 20년간 방치되어 있던 언약궤를 이제 왕도의 중심으로 모시려는 것입니다. 이는 단순한 종교적 행사가 아니라 하나님을 왕국의 중심에 모시겠다는 다윗의 신앙고백이었습니다.\n\n그런데 나곤의 타작마당에서 충격적인 일이 일어납니다. 소가 뛰는 바람에 궤가 기울어지자 웃사가 손을 내밀어 궤를 붙잡았고, 하나님께서 그를 그 자리에서 치셔서 죽게 하신 것입니다. 선한 의도로 한 행동이었지만, 하나님의 거룩함을 인간의 방식으로 다루려 한 것이 문제였습니다. 애초에 언약궤는 레위인이 어깨에 메고 운반해야 했는데, 블레셋 방식을 따라 수레에 실은 것부터가 잘못이었습니다.\n\n두려워하며 당황한 다윗은 궤를 오벧에돔의 집에 머물게 합니다. 그런데 석 달 동안 오벧에돔의 집에 놀라운 축복이 임하는 것을 보고, 다윗은 깨닫습니다. 하나님의 거룩함은 두려운 것이지만, 그분의 뜻대로 행할 때는 축복의 근원이 되신다는 것을 말입니다. 이번에는 레위인들이 궤를 메고, 여섯 걸음마다 제사를 드리며 정성스럽게 모셔옵니다.\n\n예루살렘에 도착한 다윗은 베 에봇만 입고 여호와 앞에서 힘껏 춤을 춥니다. 왕의 위엄은 내려놓고 한 명의 예배자로 서는 모습입니다. 미갈이 이를 업신여기며 조롱하지만, 다윗은 "이는 여호와 앞에서 한 것이니라"(삼하 6:21)고 담대히 고백합니다. 사람의 시선이 아닌 하나님의 시선만을 의식하는 진정한 예배자의 모습이었습니다.\n\n하나님의 거룩함을 두려워하면서도 그분과의 친밀함을 갈망하는 것, 왕의 자리에서도 기꺼이 종이 되어 춤추는 것 - 이것이 하나님의 마음에 합한 다윗의 영성이었습니다. 오늘 우리도 거룩하신 하나님께 합당한 예배를 드리되, 온 마음을 다해 그분 앞에서 기뻐 춤추는 예배자가 되기를 소망합니다.', E'오늘의 핵심\n하나님의 궤를 옮기는 과정에서 다윗은 하나님의 거룩함을 새롭게 깨닫고, 합당한 방법으로 궤를 모신 후 온 마음을 다해 하나님 앞에서 춤추며 예배합니다.\n\n묵상 질문\n1. 나는 하나님을 예배할 때 그분의 거룩함을 얼마나 의식하며 두려워하고 있나요?\n2. 사람들의 시선과 평가를 의식해서 하나님께 온전히 드리지 못한 예배는 없었나요?\n3. 다윗처럼 왕의 자리에서도 종이 되어 춤출 수 있는 겸손한 예배자가 되려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-22', E'종이 된 다윗 왕 (사무엘하 7장)', E'사무엘하 7장', E'다윗은 마침내 평안한 시간을 맞이합니다. 하나님께서 주위의 모든 원수를 무찌르시고 왕궁에 거할 수 있게 하신 것입니다. 백향목으로 지은 아름다운 궁전에 앉아 있던 다윗의 마음에 한 가지 생각이 떠오릅니다. 자신은 이렇게 좋은 집에 살고 있는데, 하나님의 궤는 여전히 휘장 가운데 있다는 것이었습니다. 이 대조가 다윗의 마음을 불편하게 했고, 하나님을 위해 성전을 짓고자 하는 소원으로 이어집니다.\n\n나단 선지자를 통해 전해진 하나님의 응답은 뜻밖이었습니다. 하나님께서는 다윗의 마음을 기쁘게 받으시면서도, 성전 건축은 그의 아들이 하게 될 것이라고 말씀하십니다. 대신 다윗에게는 그가 상상하지 못한 더 큰 약속을 주십니다. "나는 그의 나라 왕위를 영원히 견고하게 하리라"(삼하 7:13). 다윗이 하나님을 위해 집을 지으려 했지만, 오히려 하나님께서 다윗을 위해 영원한 집, 곧 왕조를 세워주시겠다는 언약이었습니다.\n\n이 압도적인 은혜 앞에서 다윗의 반응이 인상적입니다. 그는 여호와 앞에 나아가 앉아서 자신을 반복해서 ''종''이라고 부릅니다. "주 여호와여 나는 누구이오며 내 집은 무엇이기에 나를 여기까지 이르게 하셨나이까"(삼하 7:18). 온 나라가 인정하는 왕이었지만, 하나님 앞에서는 철저히 종의 자리에 선 것입니다. \n\n다윗의 기도는 자신의 보잘것없음과 하나님의 위대하심을 대비시킵니다. 목장에서 양을 치던 소년을 이스라엘의 주권자로 삼으시고, 그의 이름을 땅에서 위대한 자들의 이름처럼 만들어주시겠다는 약속 앞에서, 다윗은 오직 감사와 찬양으로 응답합니다. 이것이 바로 하나님의 마음에 합한 사람의 모습이었습니다. 높아질수록 더욱 낮아지고, 받을수록 더욱 감사하는 마음, 그것이 다윗이 가진 믿음의 비결이었습니다.', E'오늘의 핵심\n하나님께서는 성전을 건축하려는 다윗의 마음을 기쁘게 받으시고, 그의 왕조를 영원히 견고하게 하시겠다는 더 큰 언약으로 응답하십니다.\n\n묵상 질문\n1. 내가 가진 것과 하나님께 드리는 것을 비교할 때, 어떤 마음이 드나요?\n2. 하나님의 뜻이 내 계획과 다를 때, 다윗처럼 겸손히 받아들일 수 있을까요?\n3. 높은 자리에 있으면서도 ''종''이라고 고백하는 다윗의 마음을 어떻게 본받을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-23', E'종이 된 다윗 왕 (사무엘하 8장)', E'사무엘하 8장', E'사무엘하 7장에서 하나님께 영원한 왕조의 약속을 받은 다윗은 이제 그 약속의 성취를 경험하기 시작합니다. 8장은 다윗이 주변 여러 나라를 정복하는 모습을 보여주는데, 여기서 주목할 점은 "다윗이 어디로 가든지 여호와께서 이기게 하시니라"(삼하 8:6)는 표현이 반복된다는 것입니다. 이 승리들은 단순한 군사적 성공이 아니라, 하나님의 신실한 약속 이행이었습니다.\n\n다윗은 블레셋, 모압, 소바, 다메섹 아람, 에돔 등 이스라엘을 둘러싼 모든 적대 세력을 차례로 제압합니다. 이들은 모두 과거 이스라엘을 괴롭혔던 나라들이었습니다. 특히 블레셋은 사울 왕을 죽음으로 몰고 간 숙적이었고, 모압과 에돔은 이스라엘의 형제 민족이면서도 끊임없이 대적했던 나라들이었습니다. 하나님께서는 다윗을 통해 이 모든 위협을 제거하시고 이스라엘에 평화를 주셨습니다.\n\n흥미로운 것은 다윗이 전쟁에서 얻은 모든 전리품을 여호와께 드렸다는 사실입니다. 금과 은, 놋으로 된 귀중품들을 자신의 것으로 삼지 않고 하나님께 봉헌한 것입니다. 이는 훗날 솔로몬이 성전을 지을 때 사용될 재료가 되었습니다. 다윗은 비록 자신이 성전을 짓지는 못하지만, 이렇게라도 성전 건축을 위해 준비하고자 했던 것입니다.\n\n8장의 마지막 부분은 다윗의 통치 체제를 보여줍니다. 그는 온 이스라엘을 다스리며 "모든 백성에게 정의와 공의를 행"했습니다. 요압은 군사령관으로, 여호사밧은 사관으로, 사독과 아히멜렉은 제사장으로 세워 국가의 기틀을 확립했습니다. 이는 개인의 카리스마에 의존하던 사사 시대와는 완전히 다른, 체계적인 왕정 국가의 모습이었습니다.\n\n다윗의 승리는 그의 군사적 능력 때문만이 아니었습니다. 하나님께서 함께하시고 이기게 하셨기 때문입니다. 그리고 다윗은 그 승리의 영광을 하나님께 돌렸습니다. 이것이 하나님께서 다윗과 맺으신 언약이 견고하게 서 가는 과정이었습니다.', E'오늘의 핵심\n하나님께서는 다윗과 맺으신 언약대로 그가 가는 곳마다 승리하게 하시고, 다윗은 모든 전리품을 하나님께 드리며 정의와 공의로 나라를 다스립니다.\n\n묵상 질문\n1. 내 삶의 승리와 성취를 하나님의 은혜로 고백하고 있나요?\n2. 다윗처럼 내가 얻은 것들을 하나님께 드릴 마음의 준비가 되어 있나요?\n3. 하나님께서 내게 맡기신 영역에서 정의와 공의를 실천하고 있는지 돌아보았나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-25', E'종이 된 다윗 왕 (사무엘하 9장)', E'사무엘하 9장', E'평안한 시간을 맞이한 다윗의 마음에 한 가지 기억이 떠오릅니다. 사울의 집에 아직 남은 사람이 있는지 찾아보라는 다윗의 명령은 단순한 왕의 관심이 아니었습니다. 그것은 요나단과 맺었던 언약에 대한 기억이었고, 하나님의 은총을 베풀고자 하는 마음이었습니다.\n\n므비보셋은 두 발을 다 절며 로드발이라는 외진 곳에 숨어 지내고 있었습니다. 사울 왕가의 후손으로서 새 왕조에게는 위협이 될 수 있는 존재였기에, 그의 삶은 늘 불안과 두려움 속에 있었을 것입니다. 다윗의 부름을 받고 왕궁에 나아온 므비보셋이 "죽은 개 같은 나"라고 스스로를 표현한 것은 그런 절망적인 심정을 보여줍니다.\n\n그러나 다윗은 므비보셋에게 "무서워하지 말라"고 말하며 놀라운 은혜를 베풉니다. 할아버지 사울의 모든 밭을 돌려주고, 왕의 상에서 함께 먹을 자격을 부여한 것입니다. 이는 단순한 재산 회복이나 신분 보장을 넘어서는 것이었습니다. 왕의 상에서 먹는다는 것은 왕의 가족으로 받아들여졌다는 의미였습니다.\n\n다윗의 이러한 행동은 하나님께서 우리에게 베푸신 은혜의 모습을 보여줍니다. 죄로 인해 하나님께로부터 멀어진 우리를 찾아오셔서, 두려워하지 말라고 하시며, 하나님의 자녀로 회복시켜 주신 것입니다. 므비보셋이 자신의 장애나 과거의 신분 때문이 아니라 오직 다윗의 은혜로 왕의 상에 앉게 된 것처럼, 우리도 우리의 공로가 아닌 하나님의 은혜로 구원받고 하나님의 자녀가 되었습니다.\n\n시바와 그의 가족들이 므비보셋을 섬기게 된 것도 의미심장합니다. 한때 주인이었던 사울 왕가를 섬기던 시바가 이제는 다시 그 후손을 섬기게 되었지만, 이번에는 다윗의 은혜 아래에서입니다. 은혜는 이처럼 관계를 회복시키고 새로운 질서를 만들어냅니다. 오늘 우리도 받은 은혜를 기억하며, 누군가에게 그 은혜를 흘려보낼 수 있기를 소망합니다.', E'오늘의 핵심\n다윗은 요나단과의 언약을 기억하고 므비보셋을 찾아 왕의 아들처럼 대우하며, 이는 하나님께서 우리에게 베푸신 언약적 은혜를 보여줍니다.\n\n묵상 질문\n1. 내가 ''죽은 개''처럼 느껴질 때, 하나님은 나를 어떻게 부르시나요?\n2. 과거의 약속을 기억하고 지키려는 다윗의 모습에서 무엇을 배울 수 있을까요?\n3. 오늘 내가 은혜를 베풀어야 할 ''므비보셋''은 누구일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-26', E'종이 된 다윗 왕 (사무엘하 10장)', E'사무엘하 10장', E'다윗이 보낸 조문 사절단이 수치스럽게 돌아왔습니다. 암몬 왕 나하스가 죽자, 다윗은 그가 자신에게 베풀었던 은혜를 기억하며 그의 아들 하눈에게 조객을 보냈습니다. 하지만 암몬의 관리들은 이를 정탐 행위로 오해하도록 왕을 부추겼고, 하눈은 사절단의 수염을 반쯤 깎고 옷을 중간까지 잘라 돌려보내는 모욕을 가했습니다.\n\n고대 근동에서 수염은 남성의 존엄을 상징하는 것이었기에, 이는 단순한 무례를 넘어선 선전포고나 다름없었습니다. 다윗은 수치를 당한 신하들을 위로하며 여리고에 머물다 돌아오도록 배려합니다. 한편 암몬 자손들은 자신들의 행동이 가져올 결과를 알고 급히 아람 용병 2만여 명을 고용해 전쟁을 준비합니다.\n\n전투가 시작되자 요압은 전후에서 협공당하는 위기에 직면합니다. 그는 정예병을 이끌고 아람군을 맡고, 동생 아비새에게는 암몬군을 맡겨 서로 돕기로 약속합니다. 특별히 주목할 것은 요압의 신앙고백입니다. "우리가 우리 백성과 우리 하나님의 성읍들을 위하여 담대히 하자 여호와께서 선히 여기시는 대로 행하시기를 원하노라"(삼하 10:12). 전쟁의 승패를 하나님께 온전히 맡기는 믿음의 선언이었습니다.\n\n결과는 이스라엘의 완전한 승리였습니다. 아람 사람들이 도망하자 암몬 자손들도 뒤따라 도망했고, 후에 재집결한 아람 연합군도 다윗에게 대패하여 항복합니다. 다윗의 선한 의도가 오해받고 모욕당했지만, 하나님께서는 이 사건을 통해 오히려 이스라엘의 영향력을 확장시키셨습니다.\n\n우리도 때로는 선한 마음으로 행한 일이 오해받거나 거절당할 때가 있습니다. 그러나 하나님께서는 우리의 진실한 마음을 아시고, 그 상황까지도 선하게 사용하십니다. 중요한 것은 요압처럼 담대한 믿음으로 나아가되, 결과는 하나님께 맡기는 것입니다.', E'오늘의 핵심\n다윗의 선의가 오해받아 전쟁으로 이어졌지만, 하나님께서는 이를 통해 이스라엘을 더욱 강성하게 하시고 주변 나라들이 섬기게 하셨습니다.\n\n묵상 질문\n1. 내 선한 의도가 오해받았던 경험이 있나요? 그때 어떻게 반응했나요?\n2. 요압처럼 최선을 다하되 결과는 하나님께 맡기는 신앙이 필요한 상황이 있나요?\n3. 하나님께서 내 실패나 좌절을 통해서도 선을 이루신 경험이 있다면 나누어 보세요.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-27', E'시편 3편 압살롬의 반역', E'사무엘하 15장', E'압살롬이 아버지 다윗에 대한 반역의 기발을 높이 치켜듭니다. 오랜 시간 동안 꾸준히 예루살렘과 헤브론을 오가며 민심을 자신의 것으로 만들 만큼 압살롬의 계획은 치밀했습니다. 그는 아버지의 오랜 동지이자 전략가였던 아히도벨까지 포섭하여 만만치 않은 세력을 이루었습니다. 결국 다윗은 압살롬이 예루살렘에 도착하기 전에 황급히 성을 빠져나와야 했습니다. 압살롬은 예루살렘 성을 장악하고 왕으로 등극합니다. 그러나 아직 반역이 완전히 성공한 것은 아닙니다.\n다윗의 도피길에 동행하기 위해 레위 사람들과 제사장들이 하나님의 궤를 메고 쫓아옵니다. 그러나 다윗은 하나님의 궤를 돌려보내고 제사장 사독과 그의 아들 아히마아스, 제사장 아비아달과 그의 아들 요나단을 예루살렘에 남겨 놓음으로써 하나님을 향한 믿음과 뒷일을 준비하는 정치가의 노련함을 보여줍니다. 그때 압살롬 세력에 아히도벨이 가담하였다는 청천벽력 같은 소식이 들리자 다윗은 자신의 신하 가운데 아히도벨과 맞먹을 정도로 노련한 정치인 후새를 압살롬 진영에 거짓 투항시킵니다. 당시 최고의 모사였던 아히도벨, 그리고 다윗의 제안으로 거짓 투항한 후새, 이제 이들의 전략 싸움이 압살롬 반역의 성패를 결정하게 됩니다.', E'오늘의 핵심\n치밀하게 준비된 압살롬의 반역에 놀란 다윗은 황급히 예루살렘을 빠져나오면서도 믿음 가운데 반역군에 대항할 전략을 세웁니다.\n\n묵상 질문\n하나님은 다윗이 실패하고 도망칠 때도 버리지 않으셨을까요?\n내가 누군가에게 상처를 받았을 때 어떻게 대응하고 있나요?\n다윗처럼 어려움 속에서도 하나님을 신뢰하는 마음으로 기도하겠다는 다짐이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-28', E'다윗의 복귀 (사무엘하 18장)', E'사무엘하 18장', E'후새의 모략이 성공하면서 다윗은 시간을 벌어 군대를 재정비할 수 있었습니다. 다윗은 그와 함께한 백성들을 요압, 아비새, 잇대의 지휘 아래 삼분하여 조직적으로 편성합니다. 백성들의 만류로 다윗은 성읍에 머물지만, 전장으로 나가는 모든 군지휘관들에게 "나를 위하여 젊은 압살롬을 너그러이 대우하라"고 당부합니다. 반역자 압살롬에 대한 아버지의 애틋한 마음이 그대로 드러납니다.\n\n에브라임 수풀에서 벌어진 전투는 다윗군의 압도적 승리로 끝납니다. 이만 명이나 되는 압살롬의 군대가 전사했는데, 흥미롭게도 칼에 죽은 자보다 수풀에서 죽은 자가 더 많았다고 성경은 기록합니다. 하나님께서 자연까지도 사용하셔서 다윗을 도우신 것입니다. 압살롬은 도망가던 중 상수리나무에 머리가 걸려 공중에 매달리게 됩니다. 왕의 엄명을 아는 한 군사가 이를 요압에게 보고하자, 요압은 직접 나서서 압살롬의 심장을 창으로 찌릅니다.\n\n요압의 이러한 독단적 행동은 다윗의 명령에 대한 명백한 불복종이었습니다. 그는 정치적 판단으로 압살롬을 제거해야 한다고 믿었지만, 이는 왕의 권위를 무시하고 자신의 뜻대로 행한 것입니다. 승전 소식을 전하러 온 두 전령을 통해 압살롬의 죽음을 확인한 다윗은 깊은 슬픔에 빠집니다. "내 아들 압살롬아 차라리 내가 너를 대신하여 죽었더면"이라는 다윗의 통곡은 반역한 아들조차 포기할 수 없었던 아버지의 마음을 보여줍니다. 이는 죄인인 우리를 끝까지 포기하지 않으시는 하나님 아버지의 마음을 떠올리게 합니다.', E'오늘의 핵심\n반역자 압살롬의 죽음 앞에서 통곡하는 다윗의 모습은 죄인을 향한 끝없는 사랑과 긍휼을 보여주시는 하나님 아버지의 마음을 반영합니다.\n\n묵상 질문\n1. 다윗이 반역한 아들 압살롬을 향해 보인 사랑은 나에게 어떤 의미로 다가오나요?\n2. 요압처럼 자신의 판단을 하나님의 뜻보다 앞세운 적은 없었나요?\n3. 승리의 순간에도 슬퍼하는 다윗을 통해 하나님의 마음을 어떻게 이해할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-29', E'다윗의 복귀 (사무엘하 19장)', E'사무엘하 19장', E'압살롬의 죽음 소식에 다윗은 깊은 슬픔에 잠깁니다. 승리의 날이 도리어 애도의 날이 되었고, 백성들은 마치 전쟁에서 패배한 것처럼 조용히 성으로 들어갔습니다. 요압의 직언을 들은 다윗은 비로소 왕의 자리로 돌아와 성문에 앉아 백성들을 맞이합니다. 이는 왕으로서의 책임을 다시 짊어지는 순간이었습니다.\n\n다윗의 예루살렘 귀환 과정은 깨어진 관계들을 회복하는 여정이었습니다. 이스라엘 각 지파는 왕을 다시 모셔와야 한다고 논의하기 시작했고, 다윗은 특별히 자신의 지파인 유다에게 먼저 손을 내밉니다. 압살롬의 군대 장관이었던 아마사를 새로운 군사령관으로 임명하겠다는 약속을 통해 분열된 민심을 하나로 모으려 했습니다.\n\n요단강을 건너는 다윗 앞에 과거의 인물들이 나타납니다. 자신을 저주했던 시므이는 베냐민 사람 천 명과 함께 급히 내려와 용서를 구합니다. 아비새는 그를 죽여야 한다고 주장하지만, 다윗은 "내가 오늘 이스라엘의 왕이 된 것을 내가 알지 못하리요"(삼하 19:22)라며 그를 용서합니다. 이는 단순한 관용이 아니라 분열된 나라를 치유하려는 왕의 지혜였습니다.\n\n므비보셋과의 만남은 또 다른 화해의 장면을 보여줍니다. 시바의 거짓 고발로 오해받았던 그는 왕의 무사 귀환만으로도 감사하다고 고백합니다. 늙은 바르실래는 왕의 초청을 정중히 거절하며 자신의 고향으로 돌아갑니다. 이 모든 만남들은 다윗이 단순히 권력을 회복하는 것이 아니라, 상처받은 관계들을 치유하고 새로운 시작을 준비하는 과정임을 보여줍니다.', E'오늘의 핵심\n다윗의 예루살렘 귀환은 권력의 회복이 아니라 깨어진 관계들을 치유하고 분열된 민족을 하나로 모으는 화해와 용서의 여정이었습니다.\n\n묵상 질문\n1. 개인적 슬픔과 공적 책임 사이에서 균형을 잃었던 경험이 있나요?\n2. 나를 상처 준 사람을 용서하는 것이 공동체 전체를 위해 필요할 때가 있었나요?\n3. 하나님께서는 나의 실패와 상처를 통해 어떤 새로운 시작을 준비하고 계실까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-01-30', E'다윗의 복귀 (사무엘하 20장)', E'사무엘하 20장', E'압살롬의 반란이 진압되고 다윗이 예루살렘으로 돌아왔지만, 이스라엘의 분열은 끝나지 않았습니다. 베냐민 지파 비그리의 아들 세바가 나팔을 불며 "우리는 다윗과 나눌 분깃이 없다"고 외치자, 북쪽 열 지파가 다윗을 떠나 그를 따릅니다. 압살롬의 반란으로 드러난 왕국 내부의 균열이 여전히 치유되지 않은 채 남아 있음을 보여주는 장면입니다.\n\n다윗은 새로 임명한 군사령관 아마사에게 유다 군대를 소집하라고 명령하지만, 아마사가 정한 기일을 넘기자 아비새에게 요압의 군대를 이끌고 세바를 추격하게 합니다. 기브온에서 요압은 아마사를 만나 평안을 묻는 척하며 칼로 그를 죽입니다. 압살롬을 죽인 것처럼 또다시 다윗의 뜻과는 무관하게 독단적으로 행동한 것입니다. 요압에게 있어 아마사는 자신의 군사령관 자리를 빼앗은 경쟁자였기 때문입니다.\n\n세바는 벧마아가 아벨 성에 피신하고, 요압의 군대가 성을 포위합니다. 이때 한 지혜로운 여인이 나타나 요압과 협상합니다. 그녀는 아벨 성이 이스라엘에서 ''어머니 같은 성''이며 지혜의 중심지임을 상기시키면서, 한 사람 때문에 온 성읍을 멸하는 것이 옳지 않다고 설득합니다. 결국 성읍 사람들이 세바의 머리를 베어 요압에게 던짐으로써 또 다른 유혈 사태는 막을 수 있었습니다.\n\n이 장은 다윗 왕국의 행정 조직을 소개하며 마무리됩니다. 요압은 여전히 군사령관직을 유지하고 있으며, 각 부서의 책임자들이 자리를 지키고 있습니다. 겉으로는 질서가 회복된 것처럼 보이지만, 반란과 분열의 씨앗이 왕국 깊숙이 뿌리내리고 있음을 암시합니다. 하나님께서는 이러한 인간의 연약함과 권력 다툼 속에서도 당신의 뜻을 이루어 가십니다.', E'오늘의 핵심\n압살롬의 반란 이후에도 이스라엘의 분열은 계속되었으며, 세바의 반란을 통해 다윗 왕국 내부의 깊은 균열이 여전히 존재함이 드러났습니다.\n\n묵상 질문\n1. 권력과 지위를 둘러싼 갈등이 공동체에 미치는 영향을 어떻게 보고 있나요?\n2. 지혜로운 여인처럼 위기 상황에서 평화를 추구하는 중재자의 역할을 감당할 준비가 되어 있나요?\n3. 겉으로는 질서가 회복된 것처럼 보여도 내면의 상처와 분열이 남아있을 때, 진정한 화해와 치유를 위해 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-01', E'다윗의 삶의 자취 (사무엘하 23장)', E'사무엘하 23장', E'다윗의 생애가 저물어가는 시점에서 사무엘하 23장은 그의 마지막 말과 함께 그와 평생을 함께한 용사들의 이름을 기록하고 있습니다. 다윗은 자신을 "야곱의 하나님께로부터 기름 부음 받은 자"로 소개하면서도, 자신의 통치가 오직 "여호와의 영"을 통해 이루어졌음을 분명히 밝힙니다. 그가 남긴 마지막 유언은 단순한 개인의 회고가 아니라, 하나님을 경외하며 공의로 다스리는 통치자의 모습이 어떠해야 하는지를 보여주는 영적 유산이었습니다.\n\n특히 주목할 것은 다윗이 홀로 이스라엘을 다스린 것이 아니라는 점입니다. 본문은 삼십칠 명에 이르는 용사들의 이름과 그들의 공적을 상세히 기록합니다. 요셉밧세벳이 단번에 팔백 명을 쳐죽인 일, 엘르아살이 손이 칼에 붙을 때까지 블레셋과 싸운 일, 세 용사가 목숨을 걸고 베들레헴 우물물을 길어온 일 등이 생생하게 전해집니다. 이들은 단순한 군사가 아니라 다윗과 함께 하나님의 공의를 이 땅에 실현하는 동역자들이었습니다.\n\n베들레헴 우물물 사건은 특별히 다윗의 리더십을 보여줍니다. 그는 용사들이 목숨을 걸고 가져온 물을 차마 마실 수 없어 여호와께 부어드렸습니다. 이는 부하들의 헌신을 귀하게 여기는 지도자의 마음이면서, 동시에 모든 영광을 하나님께 돌리는 신앙인의 자세였습니다. 다윗의 위대함은 개인의 능력에 있지 않고, 하나님께서 예비하신 동역자들과 함께 하나님의 나라를 세워간 데 있었습니다. 하나님의 역사는 언제나 한 사람을 넘어 공동체를 통해 이루어집니다.', E'오늘의 핵심\n다윗의 마지막 말과 그와 함께한 삼십칠 용사들의 기록은 하나님의 나라가 한 개인이 아닌 신실한 공동체를 통해 세워진다는 것을 보여줍니다.\n\n묵상 질문\n1. 다윗이 용사들의 헌신을 귀하게 여긴 것처럼, 나는 함께하는 사람들의 수고를 어떻게 인정하고 있나요?\n2. 나의 삶에서 하나님의 일을 함께 이루어갈 동역자는 누구이며, 어떻게 그들과 협력할 수 있을까요?\n3. 다윗처럼 모든 성취와 영광을 하나님께 돌리는 삶을 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-02', E'다윗의 삶의 자취 (사무엘하 24장)', E'사무엘하 24장', E'다윗의 통치 말년, 그는 인생의 마지막 시험대 앞에 서게 됩니다. 여호와께서 이스라엘을 향한 진노 가운데 다윗의 마음을 움직이셨고, 다윗은 이스라엘과 유다의 인구조사를 명령합니다. 요압이 간곡히 만류했지만, 왕의 고집스러운 명령은 결국 시행되었고 아홉 달 스무 날에 걸친 조사 끝에 이스라엘의 칼을 빼는 담대한 자가 팔십만, 유다가 오십만이라는 보고가 올라옵니다.\n\n그런데 인구조사를 마친 후 다윗의 마음에 자책이 일어납니다. 그는 즉시 하나님께 자신의 죄를 고백하며 용서를 구합니다. 하나님의 선지자 갓을 통해 세 가지 재앙 중 하나를 택하라는 말씀이 전해졌을 때, 다윗은 "여호와께서는 긍휼이 크시니 우리가 여호와의 손에 빠지고 내가 사람의 손에 빠지지 아니하기를 원하노라"(삼하 24:14)고 고백합니다. 이는 징계 중에도 하나님의 긍휼을 신뢰하는 믿음의 고백이었습니다.\n\n전염병으로 칠만 명이 죽는 참혹한 재앙 중에 다윗은 백성을 위해 중보기도를 드립니다. 그는 죄를 지은 자신과 자기 집안이 벌을 받아야지 무고한 백성들이 고통받는 것을 견딜 수 없었습니다. 갓의 지시에 따라 아라우나의 타작마당에 올라간 다윗은 그곳에서 제단을 쌓기 위해 타작마당을 구입합니다. 아라우나가 모든 것을 거저 드리겠다고 했지만, 다윗은 "값 없이는 내 하나님 여호와께 번제를 드리지 아니하리라"며 정당한 값을 지불하고 구입합니다. \n\n다윗이 그곳에 제단을 쌓고 번제와 화목제를 드렸을 때, 여호와께서 그 기도를 들으시고 재앙이 그쳤습니다. 이 아라우나의 타작마당은 훗날 솔로몬이 성전을 건축하게 될 바로 그 장소였습니다. 실패와 회개, 그리고 회복의 자리가 후에 하나님을 예배하는 성전의 터가 되었다는 사실은 우리에게 깊은 은혜를 전해줍니다.', E'오늘의 핵심\n다윗은 말년의 실수로 큰 재앙을 불러왔지만, 즉각적인 회개와 백성을 위한 중보기도, 그리고 진정한 예배로 하나님과의 관계를 회복합니다.\n\n묵상 질문\n1. 내가 하나님보다 더 의지하고 자랑하려는 것은 무엇인가요?\n2. 징계의 순간에도 하나님의 긍휼을 신뢰할 수 있나요?\n3. 하나님께 드리는 예배에 나는 어떤 대가를 치르고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-03', E'하나님을 떠난 솔로몬', E'열왕기상 9장', E'솔로몬이 성전과 왕궁 건축을 모두 마쳤을 때, 하나님께서 두 번째로 나타나십니다. 첫 번째는 기브온에서 "무엇을 원하느냐"고 물으셨던 은혜로운 만남이었습니다. 그런데 이번에는 분위기가 사뭇 다릅니다. 하나님은 축복의 약속과 함께 분명한 경고를 함께 말씀하십니다. "네 아버지 다윗처럼 마음을 온전히 하여 행하면 왕위를 영원히 세우겠지만, 돌아서서 다른 신을 섬기면 이 성전이라도 던져버리겠다"고 하신 것입니다.\n\n여기서 주목할 것은 하나님의 조건입니다. "마음을 온전히 하고 바르게 하여" 행하라는 것, 그리고 "온갖 일에 순종하여" 법도와 율례를 지키라는 것입니다. 완벽한 사람이 되라는 뜻이 아니라, 마음의 방향이 하나님을 향해 온전히 놓여 있으라는 뜻입니다. 다윗도 실수가 많았지만, 그의 마음은 늘 하나님께로 돌아왔습니다. 하나님이 원하신 것은 바로 그 마음이었습니다.\n\n그러나 9장 후반부를 보면, 솔로몬의 삶에 미묘한 균열이 보이기 시작합니다. 히람에게 이스라엘의 성읍 스무 곳을 넘기고, 대규모 역군을 동원하며, 바로의 딸을 위한 궁을 따로 짓습니다. 하나님의 성전을 지은 그 손으로, 점점 세상의 영광을 쌓아가는 모습입니다. 솔로몬의 통치 전반기를 특징짓던 ''하나님을 사랑하는 마음''이 서서히 분산되기 시작한 것입니다. 이 분산된 마음은 결국 이스라엘 분열이라는 돌이킬 수 없는 결과로 이어집니다.\n\n우리의 일상도 비슷하지 않습니까. 큰 죄를 짓거나 극적으로 신앙을 버리는 것이 아니라, 바쁜 일상 속에서 마음이 조금씩 흩어지는 것입니다. 직장에서의 성취, 관계에서의 인정, 미래에 대한 계획들이 나쁜 것은 아니지만, 그것들이 마음의 중심을 차지할 때 우리는 솔로몬의 길을 걷게 됩니다. 오늘 나의 마음은 어디를 향해 있습니까? 하나님께서 "내 눈길과 내 마음이 항상 거기에 있으리라"고 말씀하신 것처럼, 우리의 눈길과 마음도 그분께 온전히 향하고 있는지 돌아보는 하루가 되길 바랍니다.', E'오늘의 핵심\n하나님은 솔로몬에게 축복과 함께 분명한 경고를 주셨지만, 솔로몬의 마음은 서서히 하나님을 떠나 세상의 영광으로 흩어지기 시작했습니다.\n\n묵상 질문\n1. 하나님께서 솔로몬에게 두 번이나 나타나신 이유는 무엇이라고 생각하십니까?\n2. 솔로몬처럼 신앙이 조금씩 식어가는 모습이 나에게도 있지는 않습니까?\n3. 하나님이 나에게 주신 경고를 더 이상 무시하지 않으려면 무엇을 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-04', E'남북분열과 여로보암의 길 (열왕기상 12장)', E'열왕기상 12장', E'다윗 왕조의 찬란했던 영광이 솔로몬 시대를 거치며 서서히 빛을 잃어가고 있었습니다. 솔로몬이 남긴 정치적 유산은 백성들에게는 무거운 멍에였고, 이제 그의 아들 르호보암이 왕위를 계승하는 순간 이스라엘의 운명이 갈림길에 서게 됩니다. 세겜에 모인 온 이스라엘 백성이 새 왕에게 간절히 호소합니다. "왕의 아버지가 우리의 멍에를 무겁게 하였으나 왕은 이제 왕의 아버지가 우리에게 시킨 고역과 매우 무거운 멍에를 가볍게 하소서"(왕상 12:4). 이것은 단순한 정치적 요구가 아니라 생존을 위한 절박한 외침이었습니다.\n\n르호보암은 먼저 아버지의 신하였던 노인들에게 자문을 구합니다. 그들의 조언은 지혜로웠습니다. 왕이 백성을 섬기는 자가 되어 좋은 말로 대답한다면, 백성들이 영원히 왕의 종이 될 것이라는 충고였습니다. 그러나 르호보암은 이 지혜로운 조언을 버리고 자신과 함께 자란 젊은이들의 의견을 따릅니다. 그들의 조언은 더욱 강압적으로 백성을 다스리라는 것이었고, 르호보암은 포악한 말로 백성들에게 대답합니다. \n\n이 어리석은 결정의 결과는 즉각적이었습니다. 온 이스라엘이 "우리가 다윗과 무슨 관계가 있느냐"라고 외치며 각자의 장막으로 돌아갔고, 통일왕국은 남북으로 분열되고 맙니다. 성경은 이 일이 "여호와께로 말미암아 난 것"이라고 기록합니다. 하나님께서는 솔로몬의 우상숭배에 대한 심판으로 이미 예고하신 일을 르호보암의 어리석음을 통해 이루신 것입니다.\n\n북왕국의 왕이 된 여로보암 역시 처음에는 하나님의 선택을 받은 사람이었습니다. 그러나 권력을 유지하려는 욕심이 그를 잘못된 길로 인도합니다. 백성들이 예루살렘 성전에 예배하러 가면 마음이 르호보암에게로 돌아갈 것을 두려워한 여로보암은 벧엘과 단에 금송아지를 만들어 세웁니다. 더 나아가 레위인이 아닌 보통 백성으로 제사장을 삼고, 하나님께서 정하신 절기마저 임의로 바꿔버립니다. 하나님의 뜻보다 정치적 계산을 앞세운 그의 선택은 북이스라엘을 우상숭배의 길로 이끄는 씨앗이 되었습니다.', E'오늘의 핵심\n르호보암의 어리석은 결정으로 통일왕국이 분열되고, 여로보암은 정치적 욕심으로 북이스라엘을 우상숭배의 길로 인도하여 하나님의 백성이 신앙의 본질에서 멀어지게 합니다.\n\n묵상 질문\n1. 지혜로운 조언을 거부하고 자신의 뜻대로 행하려는 내 모습은 없나요?\n2. 두려움 때문에 하나님의 뜻을 왜곡하거나 타협하고 있지는 않나요?\n3. 오늘 나에게 필요한 겸손한 섬김의 자세는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-05', E'남북분열과 여로보암의 길 (열왕기상 13장)', E'열왕기상 13장', E'하나님께서는 벧엘의 금송아지 제단에서 분향하는 여로보암에게 심판의 메시지를 전하기 위해 유다에서 한 선지자를 보내십니다. 이 하나님의 사람은 제단을 향해 예언합니다. 훗날 요시야라는 왕이 나타나 이 제단에서 분향하는 제사장들을 제물로 바치고 사람의 뼈를 그 위에서 사를 것이라는 무서운 심판의 말씀이었습니다. 그 징조로 제단이 갈라지고 재가 쏟아질 것이라고 선포하자, 여로보암은 분노하여 그를 잡으라고 명령합니다. 그러나 선지자를 향해 편 왕의 손이 즉시 말라버리고, 예언한 대로 제단이 갈라지며 재가 쏟아집니다.\n\n두려움에 사로잡힌 여로보암은 자신을 위해 기도해 달라고 간청하고, 하나님의 사람이 기도하자 왕의 손이 회복됩니다. 왕은 감사의 표시로 그를 왕궁에 초대하여 대접하려 하지만, 하나님의 사람은 단호히 거절합니다. 하나님께서 이곳에서는 떡도 먹지 말고 물도 마시지 말며, 왔던 길로 되돌아가지도 말라고 명하셨기 때문입니다.\n\n그런데 벧엘에 사는 한 늙은 선지자가 이 소식을 듣고 그를 뒤쫓아가 집으로 초대합니다. 하나님의 사람이 하나님의 명령을 이유로 거절하자, 늙은 선지자는 거짓말로 그를 속입니다. 천사가 자신에게 나타나 그를 데려와 대접하라고 했다는 것입니다. 결국 하나님의 사람은 속아서 그의 집에서 음식을 먹게 됩니다.\n\n식사 중에 여호와의 말씀이 늙은 선지자에게 임하여, 하나님의 명령을 어긴 하나님의 사람에게 심판을 선포합니다. 그의 시체가 조상들의 묘실에 들어가지 못할 것이라는 말씀이었습니다. 돌아가는 길에 사자가 나타나 그를 물어 죽이지만, 신기하게도 사자는 시체를 먹지도 않고 나귀를 해치지도 않은 채 그냥 서 있었습니다. 늙은 선지자는 그의 시체를 수습하여 자신의 묘실에 장사하며, 자신이 죽거든 그 옆에 묻어달라고 유언합니다. 그가 선포한 심판의 말씀이 반드시 이루어질 것을 확신했기 때문입니다.\n\n이 모든 일을 보고도 여로보암은 악한 길에서 돌이키지 않고 오히려 더욱 완고해졌습니다. 일반 백성 중에서 자원하는 사람이면 누구든지 산당의 제사장으로 삼는 죄악을 계속했고, 이로 인해 여로보암의 집은 멸망의 길로 들어서게 됩니다.', E'오늘의 핵심\n하나님의 말씀에 대한 순종은 타협할 수 없는 절대적인 것이며, 불순종은 반드시 심판을 가져온다는 엄중한 교훈을 보여줍니다.\n\n묵상 질문\n1. 하나님의 명령을 어기게 만드는 그럴듯한 유혹이 내 삶에도 있지 않나요?\n2. 표적을 보고도 회개하지 않는 여로보암의 완고함이 나에게도 있지는 않나요?\n3. 하나님의 말씀에 절대적으로 순종하기 위해 오늘 무엇을 결단하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-06', E'남북분열과 여로보암의 길 (열왕기상 14장)', E'열왕기상 14장', E'하나님의 부르심으로 북이스라엘의 초대 왕이 된 여로보암은 점차 교만해져 하나님의 명령을 거역했습니다. 이제 그 죄의 결과가 그의 가정에 나타나기 시작합니다. 아들 아비야가 병들자 여로보암은 아내를 변장시켜 선지자 아히야에게 보냅니다. 바로 그 아히야는 과거 여로보암에게 왕이 될 것을 예언했던 선지자였습니다. 그러나 늙어서 눈이 어두워진 아히야는 하나님의 계시로 모든 것을 알고 있었습니다.\n\n아히야를 통해 전해진 하나님의 메시지는 준엄했습니다. 하나님께서는 여로보암을 백성 중에서 높여 왕으로 세우시고 다윗의 나라를 찢어 그에게 주셨지만, 그는 다윗처럼 전심으로 하나님을 따르지 않았습니다. 오히려 금송아지 우상을 만들어 백성들로 하여금 죄를 짓게 했습니다. 그 결과 여로보암의 집안은 완전히 멸망하게 될 것이며, 병든 아들 아비야는 어머니가 집에 돌아가는 즉시 죽게 될 것이라고 선포됩니다. 그나마 이 아이만이 여로보암 집안에서 유일하게 하나님을 향한 선한 마음을 품었기에 정상적인 장례를 치를 수 있다는 것이 유일한 위로였습니다.\n\n한편 남유다의 르호보암도 그의 아버지 솔로몬의 잘못된 길을 그대로 따라갔습니다. 유다 백성들은 산당과 우상과 아세라 상을 세우며 가나안 족속들의 가증한 일들을 본받아 행했습니다. 그 결과 르호보암 제5년에 애굽 왕 시삭이 침입하여 성전과 왕궁의 모든 보물을 약탈해 갔습니다. 솔로몬이 만든 금 방패들까지 모두 빼앗기자 르호보암은 그 대신 놋 방패를 만들어야 했습니다. 이는 한때 영화롭던 솔로몬 왕국이 얼마나 초라하게 전락했는지를 상징적으로 보여줍니다.\n\n하나님께서는 다윗과 같은 신실한 왕을 원하셨지만, 북이스라엘의 여로보암과 남유다의 르호보암은 모두 하나님을 떠나 우상숭배의 길로 갔습니다. 그들이 하나님의 은혜를 저버린 결과는 가정의 비극과 나라의 쇠락으로 나타났습니다.', E'오늘의 핵심\n하나님을 떠나 우상을 섬긴 여로보암과 르호보암의 선택은 가정의 비극과 나라의 쇠락이라는 쓰라린 결과를 가져왔습니다.\n\n묵상 질문\n1. 여로보암이 아내를 변장시켜 보낸 것은 무엇을 두려워했기 때문일까요?\n2. 하나님께서 주신 은혜와 책임을 내가 어떻게 감당하고 있나요?\n3. 금 방패가 놋 방패로 바뀐 것처럼, 내 삶에서 잃어버린 영광은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-08', E'오므리 왕조 (열왕기상 16장)', E'열왕기상 16장', E'북이스라엘의 역사는 끊임없는 반역과 쿠데타의 연속이었습니다. 바아사가 여로보암의 집을 멸하고 왕이 되었지만, 그 역시 여로보암의 길을 따라 걸으며 백성들을 죄로 이끌었습니다. 하나님께서는 선지자 예후를 통해 바아사와 그의 집에 대한 심판을 선포하셨고, 그 말씀대로 바아사의 아들 엘라가 왕이 된 지 2년 만에 시므리의 반역으로 죽임을 당합니다. 시므리는 바아사의 온 집안을 멸절시켰는데, 이는 예후 선지자를 통해 선포된 하나님의 말씀이 그대로 성취된 것이었습니다.\n\n그러나 시므리의 통치는 겨우 7일 만에 끝나고 맙니다. 군대 지휘관 오므리가 반란을 일으켰고, 시므리는 왕궁에 불을 지르고 그 속에서 스스로 목숨을 끊었습니다. 오므리가 디브니와의 권력 다툼 끝에 왕위에 오른 후, 그는 사마리아 산을 사서 새로운 수도를 건설합니다. 정치적으로는 성공한 왕이었지만, 영적으로는 "그 전의 모든 사람보다 더욱 악하게" 행한 왕이었습니다.\n\n오므리의 뒤를 이은 아합은 시돈 왕 엣바알의 딸 이세벨과 결혼하면서 북이스라엘에 바알 숭배를 본격적으로 들여옵니다. 사마리아에 바알 신전을 짓고 제단을 쌓으며 아세라 상을 세웠습니다. 성경은 아합이 "그 이전의 이스라엘의 모든 왕보다 심히 이스라엘 하나님 여호와를 노하시게 하였더라"고 기록합니다. 북이스라엘의 영적 타락이 절정에 이른 것입니다. 이 시대에 여리고 성을 재건하려던 히엘이 여호수아의 저주대로 자녀들을 잃은 사건은, 하나님의 말씀이 여전히 살아 역사하심을 보여줍니다.', E'오늘의 핵심\n북이스라엘의 왕들이 계속해서 여로보암의 죄악된 길을 따르며 더욱 악해져 가는 가운데, 아합 시대에 이르러 바알 숭배가 국가적으로 공인되는 영적 암흑기가 시작됩니다.\n\n묵상 질문\n1. 반복되는 죄의 역사 속에서도 하나님의 말씀은 어떻게 성취되고 있나요?\n2. 정치적 성공과 영적 실패의 대조가 내 삶에 주는 교훈은 무엇인가요?\n3. 악이 점점 더해가는 시대에 신앙인으로서 어떻게 살아가야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-09', E'오므리 왕조 (열왕기상 17장)', E'열왕기상 17장', E'북이스라엘이 바알 숭배로 물들어 가던 그때, 길르앗의 디셉 출신 엘리야가 아합 왕 앞에 나타납니다. 그는 단호하게 선언합니다. "내 말이 없으면 수 년 동안 비도 이슬도 있지 아니하리라"(왕상 17:1). 풍요와 다산의 신이라 여겨지던 바알의 무력함을 드러내시려는 하나님의 계획이었습니다. \n\n하나님께서는 엘리야를 그릿 시냇가로 인도하셨고, 그곳에서 까마귀들이 아침저녁으로 떡과 고기를 날라다 주었습니다. 부정한 짐승으로 여겨지던 까마귀가 하나님의 종을 먹이는 도구가 되었다는 것은 놀라운 역설입니다. 시내가 마른 후에는 시돈 땅 사르밧의 한 과부에게로 가라고 하셨습니다. 이세벨의 고향인 시돈, 바알 숭배의 중심지로 엘리야를 보내신 것입니다.\n\n사르밧 과부는 마지막 남은 가루와 기름으로 아들과 함께 최후의 식사를 준비하려던 참이었습니다. 엘리야는 그녀에게 먼저 자신을 위해 작은 떡을 만들어 달라고 요청합니다. 인간적으로는 무리한 요구였지만, 과부는 순종했고 그 결과 통의 가루와 병의 기름이 떨어지지 않는 기적을 경험했습니다. 하나님께서는 이방 땅의 과부를 통해서도 당신의 종을 돌보실 수 있음을 보여주셨습니다.\n\n더 놀라운 일이 이어집니다. 과부의 아들이 숨을 거두자 엘리야는 그 아이를 안고 다락으로 올라가 간절히 기도했습니다. 세 번이나 아이 위에 몸을 펴서 엎드리며 부르짖었을 때, 하나님께서는 그 아이의 생명을 되돌려 주셨습니다. 이를 본 과부는 "당신의 입에 있는 여호와의 말씀이 진실한 줄 아노라"고 고백합니다. \n\n가뭄의 심판 가운데서도 하나님께서는 당신의 종을 보호하시고, 믿음으로 순종하는 이방인까지도 축복하셨습니다. 바알이 줄 수 없는 생명과 공급의 능력을 참 하나님만이 주실 수 있음을 분명히 보여주신 것입니다.', E'오늘의 핵심\n하나님께서는 바알 숭배에 빠진 이스라엘을 가뭄으로 심판하시면서도, 엘리야와 순종하는 이방인 과부를 기적적으로 돌보시며 당신만이 참 신이심을 증명하십니다.\n\n묵상 질문\n1. 하나님께서 까마귀와 이방인 과부를 통해 엘리야를 돌보신 것이 우리에게 주는 교훈은 무엇일까요?\n2. 사르밧 과부처럼 마지막 남은 것까지 하나님께 드릴 수 있는 믿음이 내게 있나요?\n3. 오늘날 우리가 의지하는 ''바알''은 무엇이며, 참된 생명의 근원은 어디에 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-10', E'오므리 왕조와 엘리야의 사역 (열왕기상 18장)', E'열왕기상 18장', E'기근이 시작된 지 삼 년째, 하나님은 엘리야에게 아합 앞에 나타나라고 명하십니다. 그동안 엘리야의 예언대로 비가 내리지 않았고, 아합은 엘리야를 찾아 온 나라를 뒤졌지만 찾을 수 없었습니다. 흥미롭게도 하나님은 왕궁 관리인 오바댜를 통해 엘리야와 아합의 만남을 주선하십니다. 오바댜는 이세벨이 여호와의 선지자들을 학살할 때 백 명을 굴에 숨겨 보호했던 신실한 신앙인이었습니다. 악한 왕궁 한복판에서도 하나님을 경외하는 사람이 있었다는 사실은 우리에게 위로와 도전을 줍니다.\n\n아합은 엘리야를 만나자마자 "이스라엘을 괴롭게 하는 자"라고 비난합니다. 그러나 엘리야는 단호하게 진짜 문제는 여호와의 명령을 버리고 바알을 따른 왕실에 있음을 지적합니다. 그리고 갈멜 산에서 누가 참 하나님인지 증명하자고 제안합니다. \n\n갈멜 산에 모인 백성 앞에서 엘리야는 "너희가 어느 때까지 둘 사이에서 머뭇머뭇 하려느냐"라고 일갈합니다. 당시 백성들은 여호와도 섬기고 바알도 섬기는 혼합주의에 빠져 있었습니다. 바알의 선지자 450명이 아침부터 저녁까지 춤추고 소리치며 자해까지 했지만 아무 응답이 없었습니다. 반면 엘리야는 무너진 여호와의 제단을 열두 돌로 다시 쌓고, 제물에 물을 세 번이나 부은 뒤 조용히 기도했습니다. "주께서 이스라엘 중에서 하나님이신 것과... 이 백성에게 주 여호와는 하나님이신 것과 주는 그들의 마음을 되돌이키심을 알게 하옵소서"(왕상 18:36-37). \n\n그러자 하늘에서 불이 내려와 번제물과 나무뿐 아니라 돌과 물까지 삼켜버렸습니다. 이 압도적인 광경을 본 백성들은 비로소 "여호와 그는 하나님이시로다"라고 고백합니다. 갈멜 산의 대결은 단순한 종교적 시위가 아니라, 혼합주의에 빠진 백성의 마음을 하나님께로 돌이키려는 하나님의 사랑의 표현이었습니다.', E'오늘의 핵심\n갈멜 산에서 하나님은 압도적인 불의 응답으로 자신이 유일한 참 하나님이심을 증명하시고, 머뭇거리던 백성들의 마음을 돌이키셨습니다.\n\n묵상 질문\n1. 악한 환경 속에서도 신앙을 지켰던 오바댜처럼, 내가 속한 곳에서 하나님을 경외하며 살아가고 있나요?\n2. 내 삶에 여호와도 섬기고 세상도 섬기는 ''영적 혼합주의''는 없는지 돌아볼 때입니다. 무엇을 결단해야 할까요?\n3. 엘리야의 기도처럼 하나님이 내 삶의 유일한 주인이심을 드러내는 기도를 드리고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-11', E'오므리 왕조와 엘리야의 사역 (열왕기상 19장)', E'열왕기상 19장', E'갈멜 산에서의 놀라운 승리가 있은 직후, 이세벨의 살해 위협을 들은 엘리야는 두려움에 사로잡혀 도망칩니다. 850명의 거짓 선지자들과 맞서 하늘에서 불을 내린 바로 그 선지자가 한 여인의 협박 앞에서 무너진 것입니다. 엘리야는 유다 브엘세바까지 도망친 후, 홀로 광야로 들어가 로뎀 나무 아래에서 차라리 죽기를 간구합니다. "나는 내 조상들보다 낫지 못하니이다"라는 그의 탄식에는 극도의 피로감과 절망이 묻어납니다.\n\n그러나 하나님은 지쳐 쓰러진 엘리야를 꾸짖지 않으셨습니다. 오히려 천사를 보내 그를 어루만지며 "일어나서 먹으라"고 하시고, 숯불에 구운 떡과 물을 예비해 주셨습니다. 두 번에 걸친 하나님의 세심한 돌봄은 엘리야에게 호렙 산까지 40일을 갈 수 있는 힘을 주었습니다. 호렙 산 굴에서 엘리야는 자신만 홀로 남았다고 하소연하지만, 하나님은 강한 바람도, 지진도, 불도 아닌 세미한 음성으로 찾아오십니다. 요란한 기적이 아니라 고요한 임재로 다가오신 것입니다.\n\n하나님은 엘리야에게 새로운 사명을 주십니다. 하사엘과 예후와 엘리사에게 기름을 부어 각각의 역할을 맡기라는 것입니다. 그리고 놀라운 사실을 알려주십니다. "내가 이스라엘 가운데에 칠천 명을 남기리니 다 바알에게 무릎을 꿇지 아니하고 다 바알에게 입맞추지 아니한 자니라." 엘리야가 혼자라고 생각했을 때, 하나님께서는 이미 7천 명의 신실한 백성을 보존하고 계셨던 것입니다.\n\n엘리야는 즉시 순종하여 엘리사를 찾아갑니다. 열두 겨릿소로 밭을 갈던 부유한 농부 엘리사는 엘리야의 부름을 받자 주저 없이 소를 잡아 백성들과 나누어 먹고, 과거와 완전히 결별한 후 엘리야를 따릅니다. 지친 선지자에게 하나님은 쉼과 새 힘을 주셨을 뿐 아니라, 함께 짐을 나누어질 동역자까지 예비해 주신 것입니다. 승리의 순간에도, 절망의 순간에도 변함없이 우리를 돌보시는 하나님의 신실하심이 이 본문 전체를 관통하고 있습니다.', E'오늘의 핵심\n갈멜 산의 승리 후 두려움에 무너진 엘리야를 하나님은 떡과 물로 회복시키시고, 세미한 음성으로 찾아오셔서 새로운 사명과 동역자를 주셨습니다.\n\n묵상 질문\n1. 영적 승리 후에 찾아온 두려움과 무력감을 경험한 적이 있다면, 그때 하나님은 어떤 방법으로 나를 회복시키셨나요?\n2. 하나님께서 강한 바람이나 지진, 불이 아닌 세미한 음성으로 엘리야를 만나신 것이 우리에게 주는 교훈은 무엇일까요?\n3. 혼자라고 생각될 때, 하나님께서 이미 예비하신 동역자나 신앙의 공동체를 발견한 경험이 있으신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-12', E'엘리야에서 엘리사로 (열왕기하 1장)', E'열왕기하 1장', E'아합의 아들 아하시야가 왕이 되었지만, 성경이 기록하는 그의 행적은 놀랍도록 단순합니다. 다락 난간에서 떨어져 병이 들자 이스라엘의 하나님이 아닌 에그론의 신 바알세붑에게 물으러 사자를 보낸 것, 그것이 전부입니다. 왕이 병들었을 때 가장 먼저 찾아야 할 분은 언약의 하나님이셨지만, 아하시야는 이방 신에게로 향했습니다. 이는 단순한 종교적 혼합주의를 넘어, 하나님의 존재 자체를 부정하는 배교 행위였습니다.\n\n"이스라엘에 하나님이 없어서 너희가 에그론의 신 바알세붑에게 물으러 가느냐"(왕하 1:3)는 엘리야의 질책은 아하시야 개인만이 아니라, 하나님을 잊어버린 시대 전체를 향한 탄식이었습니다. 북이스라엘의 왕이 공개적으로 이방 신을 찾는 모습은 온 나라가 얼마나 깊은 영적 타락에 빠져 있는지를 보여줍니다.\n\n하나님께서는 엘리야를 통해 즉각적인 심판의 메시지를 전하셨습니다. 아하시야는 그 침상에서 일어나지 못하고 죽을 것이라는 선언이었습니다. 그러나 왕은 이 경고를 듣고도 회개하지 않았습니다. 오히려 군대를 보내 엘리야를 잡아오려 했습니다. 두 차례에 걸쳐 오십부장과 군사들이 하늘에서 내린 불에 타 죽는 무서운 심판이 있었지만, 왕의 마음은 여전히 완고했습니다.\n\n세 번째 오십부장의 겸손한 간구 앞에서야 엘리야는 왕에게 직접 하나님의 말씀을 전했습니다. 그러나 이미 때는 늦었습니다. 아하시야는 선언된 대로 죽음을 맞이했고, 그의 짧은 통치는 영적 실패의 기록으로만 남았습니다.\n\n이 사건은 우리에게 중요한 교훈을 줍니다. 위기의 순간에 우리가 먼저 찾는 것이 무엇인지가 우리의 진짜 믿음을 드러낸다는 사실입니다. 병들었을 때, 어려움을 만났을 때, 우리는 어디로 먼저 향하고 있습니까? 현대의 바알세붑은 물질만능주의일 수도, 인간의 지혜일 수도, 세상의 권세일 수도 있습니다. 하나님께서는 지금도 우리에게 묻고 계십니다. "너희에게 하나님이 없느냐?"', E'오늘의 핵심\n아하시야가 병들었을 때 하나님이 아닌 이방 신을 찾은 것은 북이스라엘의 깊은 영적 타락을 보여주며, 하나님께서는 이에 대해 즉각적인 심판으로 응답하셨습니다.\n\n묵상 질문\n1. 내가 위기를 만날 때 가장 먼저 의지하는 것은 무엇인가요?\n2. 하나님보다 앞서 찾게 되는 현대의 ''바알세붑''은 무엇일까요?\n3. 영적 경고를 받았을 때 어떻게 반응하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-13', E'엘리야에서 엘리사로 (열왕기하 2장)', E'열왕기하 2장', E'여호와께서 엘리야를 하늘로 올리시려는 날이 이르렀습니다. 길갈에서 벧엘로, 벧엘에서 여리고로, 여리고에서 요단까지 이어지는 여정은 단순한 이동이 아니라 사명이 계승되는 거룩한 과정이었습니다. 엘리야는 세 번이나 "여기 머물라"고 엘리사를 만류했지만, 엘리사는 "여호와께서 살아 계심과 당신의 영혼이 살아 있음을 두고 맹세하노니 내가 당신을 떠나지 아니하겠나이다"라고 답하며 끝까지 스승의 곁을 지켰습니다. 이는 단순한 제자의 충성심을 넘어서는 것이었습니다. 하나님의 역사를 이어받겠다는 간절한 갈망이 그를 붙들고 있었던 것입니다.\n\n요단강 앞에서 엘리야가 겉옷으로 물을 치자 물이 갈라졌습니다. 모세가 홍해를 가른 것처럼, 여호수아가 요단을 건넌 것처럼, 하나님의 능력이 여전히 그의 종과 함께하심을 보여주는 표징이었습니다. 건너편에서 엘리사가 구한 것은 "당신의 성령이 하시는 역사가 갑절이나 내게 있게 하소서"(왕하 2:9)라는 것이었습니다. 재물도 명예도 아닌, 오직 하나님의 일을 감당할 영적 능력을 구했습니다.\n\n불수레와 불말들이 나타나 엘리야가 회오리바람으로 하늘로 올라갔을 때, 엘리사는 "내 아버지여 내 아버지여 이스라엘의 병거와 그 마병이여"라고 외쳤습니다. 한 시대를 지켜온 신앙의 거인이 떠나는 순간이었습니다. 그러나 떨어진 겉옷을 주워 든 엘리사가 요단강 물을 치며 "엘리야의 하나님 여호와는 어디 계시니이까"라고 외쳤을 때, 물이 다시 갈라졌습니다. 하나님의 역사는 사람에게 매이지 않습니다. 엘리야는 떠났지만, 하나님께서는 엘리사를 통해 계속 일하십니다.\n\n새로운 사역의 시작은 여리고의 나쁜 물을 고치는 것이었습니다. 새 그릇에 담긴 소금으로 물의 근원을 치유하시는 하나님의 능력은 죽음과 불모의 땅에 생명을 가져왔습니다. 벧엘에서 일어난 아이들의 조롱과 그에 따른 심판은 하나님의 종을 대하는 태도가 곧 하나님을 대하는 태도임을 엄중히 가르쳐 줍니다.\n\n오늘도 하나님께서는 당신의 일을 이어갈 사람들을 찾고 계십니다. 엘리사처럼 끝까지 따르는 결단과 영적 능력을 사모하는 마음이 있을 때, 우리도 이 시대에 하나님의 도구로 쓰임받을 수 있습니다.', E'오늘의 핵심\n엘리야의 승천과 함께 그의 사역이 엘리사에게 계승되며, 하나님의 구원 역사는 사람이 바뀌어도 멈추지 않고 계속됨을 보여줍니다.\n\n묵상 질문\n1. 엘리사가 끝까지 엘리야를 따른 것처럼, 나는 하나님의 부르심에 끝까지 순종하고 있나요?\n2. "갑절의 영"을 구한 엘리사처럼, 나는 무엇보다 영적인 능력을 사모하고 있나요?\n3. 하나님께서 내 삶을 통해 이루기 원하시는 사역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-15', E'히스기야의 개혁 (열왕기하 3장)', E'열왕기하 3장', E'아합의 아들 여호람이 북이스라엘의 왕이 되었을 때, 그는 부모와는 달리 바알의 주상을 제거했습니다. 하지만 여전히 여로보암이 세운 금송아지는 그대로 두었습니다. 부분적인 개혁은 진정한 변화를 가져오지 못했고, 하나님과의 관계도 온전히 회복되지 않았습니다.\n\n그동안 조공을 바치던 모압이 아합의 죽음을 기회로 삼아 반란을 일으켰습니다. 여호람은 유다의 여호사밧과 에돔 왕과 연합하여 모압을 치러 나섰지만, 에돔 광야를 우회하는 7일간의 행군 끝에 물이 떨어지는 위기에 봉착했습니다. 이스라엘 왕은 절망했지만, 여호사밧은 여호와의 선지자를 찾았고, 그들은 엘리사를 만나게 됩니다.\n\n엘리사는 우상을 섬기는 이스라엘 왕에게는 냉담했지만, 여호사밧의 신앙을 보아서 하나님의 뜻을 구했습니다. "너희가 바람도 보지 못하고 비도 보지 못하되 이 골짜기에 물이 가득하여 너희와 너희 가축과 짐승이 마시리라"(왕하 3:17)는 하나님의 말씀대로, 다음날 아침 에돔 쪽에서 물이 흘러와 골짜기를 가득 채웠습니다. \n\n붉은 흙에 비친 햇빛으로 물이 핏빛처럼 보였고, 모압 군대는 이를 연합군끼리 싸워서 흘린 피로 착각했습니다. 방심한 채 노략하러 온 모압군은 대패했고, 모압 왕은 절망적인 상황에서 자기 맏아들을 번제로 드리는 극단적 선택을 했습니다. 이 충격적인 장면 앞에서 이스라엘 연합군은 철수했습니다.\n\n하나님께서는 불완전한 신앙을 가진 왕들에게도 은혜를 베푸셨지만, 진정한 승리는 온전한 순종에서 오는 것임을 이 사건은 보여줍니다. 부분적인 개혁, 정치적 동맹, 군사력만으로는 참된 평화를 얻을 수 없습니다. 하나님과의 온전한 관계 회복이 먼저입니다.', E'오늘의 핵심\n여호람의 부분적 개혁과 정치적 연합으로 얻은 승리는 불완전했고, 하나님께서는 불순종하는 왕에게도 은혜를 베푸시지만 온전한 회개와 순종을 원하십니다.\n\n묵상 질문\n1. 나의 신앙생활에서 바알은 제거했지만 금송아지는 남겨둔 영역이 있나요?\n2. 위기의 때에 먼저 하나님의 말씀을 구하는 여호사밧의 믿음이 내게 있나요?\n3. 하나님의 은혜를 체험하고도 온전한 헌신으로 나아가지 못하는 이유는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-16', E'히스기야의 개혁 (열왕기하 4장)', E'열왕기하 4장', E'엘리야의 뒤를 이은 엘리사의 사역은 고통받는 이스라엘 백성들에게 하나님의 살아계심을 보여주는 표적들로 가득합니다. 열왕기하 4장은 특별히 절망적인 상황에 처한 사람들을 향한 하나님의 긍휼하심을 엘리사를 통해 보여줍니다.\n\n먼저 등장하는 선지자의 과부는 남편이 남긴 빚 때문에 두 아들을 종으로 빼앗길 위기에 처해 있습니다. 엘리사는 그녀에게 빈 그릇을 많이 빌려오라고 지시하고, 그녀가 가진 기름 한 그릇으로 모든 빈 그릇을 채우는 기적을 행합니다. 이 기적은 단순히 경제적 어려움을 해결하는 데 그치지 않고, 하나님께서 과부와 고아를 돌보시는 분이심을 분명히 보여줍니다.\n\n수넴 여인의 이야기는 더욱 극적입니다. 엘리사를 극진히 대접했던 이 여인은 엘리사의 예언대로 아들을 얻지만, 그 아이가 갑작스럽게 죽음을 맞이합니다. 절망적인 상황에서도 그녀는 엘리사에게 달려가고, 엘리사는 직접 아이의 몸 위에 엎드려 기도함으로써 생명을 되살립니다. "아이가 일곱 번 재채기 하고 눈을 뜨는지라"(왕하 4:35)는 표현은 하나님께서 주시는 생명의 회복이 얼마나 완전한지를 보여줍니다.\n\n마지막으로 길갈에서의 독초 사건은 흉년으로 굶주린 선지자의 제자들에게 일어난 위기를 다룹니다. 잘못 채취한 들포도로 인해 죽음의 독이 든 국을 먹게 된 상황에서, 엘리사는 밀가루를 넣어 해독시킵니다. 이 모든 기적들은 하나님께서 당신의 백성들의 일상적인 필요 - 경제적 어려움, 자녀의 생명, 일용할 양식 - 에 깊이 관심을 가지고 계심을 보여줍니다.', E'오늘의 핵심\n하나님께서는 엘리사를 통해 과부의 경제적 위기, 수넴 여인의 죽은 아들, 선지자들의 굶주림이라는 절망적 상황을 기적으로 해결하시며 당신의 긍휼하심을 나타내십니다.\n\n묵상 질문\n1. 나의 작은 ''기름 한 그릇''으로 하나님께서 어떤 기적을 행하실 수 있을까요?\n2. 절망적인 상황에서도 수넴 여인처럼 믿음으로 나아갈 용기가 있나요?\n3. 일상의 필요를 채우시는 하나님의 손길을 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-17', E'히스기야의 개혁 (열왕기하 5장)', E'열왕기하 5장', E'아람의 군대 장관 나아만은 큰 용사였지만 나병으로 고통받고 있었습니다. 그의 집에서 수종들던 이스라엘 소녀가 사마리아의 선지자를 언급하자, 나아만은 왕의 친서와 많은 예물을 가지고 이스라엘로 향합니다. 그러나 이스라엘 왕은 아람 왕의 편지를 읽고 당황하여 옷을 찢었습니다. 병을 고치는 것은 하나님의 영역인데 자신에게 그런 요구를 하는 것은 전쟁의 빌미를 찾는 것이라 생각했기 때문입니다.\n\n이 소식을 들은 엘리사는 나아만을 자신에게 보내라고 전합니다. 그런데 엘리사는 직접 나와 맞이하지도 않고 사자를 통해 요단 강에 일곱 번 몸을 씻으라는 단순한 처방만 전달합니다. 자신의 지위와 가져온 예물에 걸맞은 대접을 기대했던 나아만은 분노하여 돌아가려 했습니다. 다메섹의 아바나와 바르발 강이 요단 강보다 깨끗한데 왜 굳이 그곳에서 씻어야 하느냐는 것이었습니다.\n\n그러나 종들의 간곡한 권면을 들은 나아만은 마음을 돌이켜 순종합니다. 요단 강에 일곱 번 몸을 잠그자 그의 살이 어린아이의 살같이 회복되었습니다. 치유받은 나아만은 이스라엘의 하나님만이 참 신임을 고백하며 앞으로는 여호와께만 제사드리겠다고 서원합니다. 엘리사가 예물을 거절하자 나아만은 노새 두 마리에 실을 흙이라도 가져가기를 청합니다. 이스라엘의 흙 위에서 여호와께 예배드리고자 하는 그의 신실한 마음이 드러납니다.\n\n그러나 엘리사의 사환 게하시는 탐욕에 눈이 멀어 거짓말로 나아만에게서 은과 옷을 받아냅니다. 모든 것을 알고 있던 엘리사는 게하시에게 나아만의 나병이 대대로 이르리라 선언합니다. 하나님의 은혜를 값없이 받은 나아만과 달리, 게하시는 그 은혜를 이용하여 이득을 취하려다 심판을 받게 됩니다. 참된 치유는 겸손한 순종을 통해 임하며, 하나님의 은혜는 결코 매매의 대상이 될 수 없음을 보여주는 사건입니다.', E'오늘의 핵심\n이방인 나아만은 단순해 보이는 말씀에 순종하여 치유받고 참 하나님을 만났지만, 게하시는 탐욕으로 인해 도리어 나병의 저주를 받게 됩니다.\n\n묵상 질문\n1. 내가 기대하는 방법과 다른 하나님의 처방 앞에서 어떻게 반응하고 있나요?\n2. 나아만의 종들처럼 교만을 내려놓도록 권면해주는 사람이 내 곁에 있나요?\n3. 하나님의 은혜를 값없이 나누는 삶과 이득으로 삼는 삶의 차이는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-18', E'오므리 왕조와 엘리사의 사역 (열왕기하 6장)', E'열왕기하 6장', E'엘리사의 사역은 거창한 무대가 아닌 일상의 필요에서 시작됩니다. 선지자의 제자들이 거처가 좁다며 요단강에서 나무를 베어 새 처소를 짓겠다고 할 때, 엘리사는 기꺼이 동행합니다. 그런데 한 제자가 빌려온 쇠도끼를 물에 빠뜨리고 절박하게 외칩니다. 엘리사가 나뭇가지를 물에 던지자 쇠도끼가 떠오르는 기적이 일어났습니다. 빌린 도구 하나의 상실까지도 하나님께서 돌아보신다는 사실이 우리에게 큰 위로를 줍니다.\n\n곧이어 본문은 국가적 위기로 전환됩니다. 아람 왕이 이스라엘을 공격하려 할 때마다 엘리사가 미리 왕에게 알려 화를 면하게 했습니다. 이에 분노한 아람 왕이 군대를 보내 도단성을 포위하자, 엘리사의 사환은 두려움에 떨었습니다. 그러나 엘리사는 "우리와 함께 한 자가 그들과 함께 한 자보다 많으니라"라고 선포합니다. 하나님께서 사환의 눈을 열어주시자 불말과 불병거가 산에 가득한 것이 보였습니다. 육신의 눈에는 위기로만 보이던 상황이 영적인 눈으로는 하나님의 보호하심으로 가득했던 것입니다.\n\n더욱 놀라운 것은 엘리사가 눈이 어두워진 아람 군사들을 사마리아로 인도한 후의 일입니다. 이스라엘 왕이 그들을 치려 하자 엘리사는 오히려 떡과 물로 대접하여 돌려보내라고 합니다. 이 은혜의 행동이 전쟁을 멈추게 했습니다. 그러나 이후 벤하닷의 재침으로 사마리아가 극심한 기근에 빠지자, 상황은 급변합니다. 자식을 잡아먹는 참혹한 지경에 이르자 왕은 "이 재앙이 여호와께로부터 나왔으니 어찌 더 여호와를 기다리리요"라며 절망합니다.\n\n이 장면들은 하나님의 일하심에 대한 상반된 반응을 보여줍니다. 엘리사는 보이지 않는 하나님의 군대를 믿음으로 바라보았고, 원수까지도 은혜로 대했습니다. 반면 이스라엘 왕은 극한의 상황에서 하나님을 향한 신뢰를 포기했습니다. 하나님께서는 작은 일상의 문제부터 국가의 존망이 걸린 위기까지 동일하게 일하십니다. 문제는 우리가 그 일하심을 끝까지 신뢰하느냐에 있습니다.', E'오늘의 핵심\n하나님은 빌린 도끼 하나의 작은 문제에서부터 국가적 위기에 이르기까지 동일하게 일하시며, 믿음의 눈으로 바라보는 자에게 담대함과 지혜를 주십니다.\n\n묵상 질문\n1. 나는 일상의 작은 문제들도 하나님께 아뢰며 그분의 도우심을 구하고 있습니까?\n2. 위기의 순간에 보이는 현실만 바라볼 것인가, 보이지 않는 하나님의 일하심을 신뢰할 것인가?\n3. 원수에게까지 은혜를 베푸는 것이 오히려 평화를 가져온다는 진리를 내 삶에 어떻게 적용할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-19', E'오므리 왕조와 엘리사의 사역 (열왕기하 7장)', E'열왕기하 7장', E'극심한 기근으로 사마리아 성이 죽음의 그늘에 잠겨 있을 때, 엘리사는 놀라운 하나님의 약속을 전합니다. "내일 이맘때에 사마리아 성문에서 고운 밀가루 한 스아를 한 세겔로 매매하고 보리 두 스아를 한 세겔로 매매하리라." 인육을 먹는 지경에 이른 절망적 상황에서 선포된 이 말씀은 너무나 비현실적으로 들렸습니다. 왕의 장관은 "여호와께서 하늘에 창을 내신들 어찌 이런 일이 있으리요"라며 조롱했고, 엘리사는 그가 기적을 눈으로 보되 누리지 못할 것이라고 선언합니다.\n\n하나님의 구원은 전혀 예상치 못한 방법으로 시작됩니다. 성문 밖에서 죽음을 기다리던 네 명의 나병환자가 절박한 마음으로 아람 진영에 들어갔을 때, 그곳은 이미 텅 비어 있었습니다. 하나님께서 아람 군대에게 병거와 말과 큰 군대의 소리를 듣게 하셔서 그들이 모든 것을 버리고 도망쳤던 것입니다. 나병환자들은 처음에는 은금과 의복을 숨겼지만, 곧 양심의 가책을 느끼고 "오늘은 아름다운 소식이 있는 날이거늘 우리가 침묵하고 있도다"라며 성으로 돌아가 이 기쁜 소식을 전합니다.\n\n왕은 처음에 이것이 아람의 함정이라고 의심했지만, 정탐꾼을 보내 확인한 후 백성들이 아람 진영을 노략하게 합니다. 그 결과 엘리사가 예언한 대로 정확히 이루어졌습니다. 그러나 하나님의 말씀을 조롱했던 장관은 성문에서 백성들에게 밟혀 죽음으로써, 불신앙의 결과가 무엇인지를 보여주는 비극적 증거가 되었습니다. 이 사건은 우리에게 분명한 교훈을 줍니다. 하나님의 약속은 인간의 상식과 계산을 뛰어넘는 방법으로 성취되며, 그분의 말씀을 신뢰하는 자에게는 구원이, 조롱하는 자에게는 심판이 임한다는 것입니다.', E'오늘의 핵심\n하나님은 가장 절망적인 순간에도 약속을 신실하게 이루시며, 그분의 구원은 종종 우리의 예상을 뛰어넘는 방법으로 임합니다.\n\n묵상 질문\n1. 현재 내가 직면한 어려움 속에서도 하나님의 약속을 신뢰하고 있습니까?\n2. 나병환자들처럼 받은 은혜와 기쁜 소식을 다른 사람과 나누고 있습니까?\n3. 하나님의 말씀에 대한 나의 태도는 신뢰입니까, 아니면 의심입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-20', E'오므리 왕조와 엘리사의 사역 (열왕기하 8장)', E'열왕기하 8장', E'하나님의 섭리는 때로 우리가 예상하지 못한 방식으로 나타납니다. 엘리사가 수넴 여인에게 7년 기근을 예고하며 블레셋으로 피난을 권했을 때, 그것은 단순한 재난 회피가 아니었습니다. 7년 후 여인이 돌아와 자기 집과 전토를 되찾으려 왕에게 호소하러 갔을 때, 놀랍게도 게하시가 왕에게 바로 그 여인의 아들을 살린 기적을 이야기하고 있었습니다. 이 절묘한 타이밍은 우연이 아니라 하나님의 완벽한 시간표였습니다. 왕은 즉시 그녀의 모든 소유와 7년간의 소출까지 돌려주라고 명령합니다.\n\n한편 다메섹에서는 병든 벤하닷 왕이 엘리사에게 자신의 운명을 묻습니다. 엘리사는 하사엘을 통해 "왕이 반드시 나으리라"고 전하면서도 "그가 반드시 죽으리라"는 모순된 메시지를 전합니다. 병은 나을 수 있지만, 하사엘의 손에 죽게 될 것을 미리 보신 것입니다. 엘리사가 하사엘을 바라보며 울었던 것은 그가 이스라엘에게 행할 잔혹한 일들을 보았기 때문입니다. "당신의 개 같은 종이 무엇이기에"라고 겸손을 가장했던 하사엘은 결국 주인을 살해하고 왕위를 찬탈합니다.\n\n남왕국 유다의 상황도 암울합니다. 여호람과 아하시야는 북왕국의 악한 왕들처럼 행했고, 특히 아합의 딸과 손녀가 왕비가 되면서 바알 숭배가 유다에까지 침투했습니다. 에돔이 반란을 일으키고 립나도 배반하는 등 왕국이 흔들렸지만, 하나님은 다윗과의 언약 때문에 유다를 완전히 멸하지는 않으셨습니다. "그와 그의 자손에게 항상 등불을 주겠다"는 약속이 악한 왕들의 시대에도 여전히 유효했던 것입니다.\n\n이 모든 이야기가 보여주는 것은 인간의 악함 속에서도 하나님의 주권적 통치는 멈추지 않는다는 사실입니다. 수넴 여인에게는 때를 맞춰 은혜를 베푸시고, 악을 행할 자들의 계획도 미리 아시며, 언약에 신실하셔서 심판 중에도 긍휼을 잊지 않으십니다. 역사의 주관자이신 하나님은 오늘도 그분의 방법으로, 그분의 시간에 일하고 계십니다.', E'오늘의 핵심\n하나님은 역사의 주관자로서 인간의 악함 속에서도 주권적으로 통치하시며, 때를 따라 은혜를 베푸시고 언약에 신실하게 긍휼을 베푸십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 완벽한 타이밍을 경험한 적이 있나요? 그때를 돌아보며 감사할 수 있을까요?\n2. 악이 승리하는 것처럼 보이는 상황에서도 하나님의 주권을 신뢰할 수 있을까요?\n3. 하나님의 언약적 신실하심이 오늘 나에게 어떤 위로와 소망을 줍니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-22', E'요아스의 치적과 여로보암 2세 (열왕기하 9장)', E'열왕기하 9장', E'열왕기하 9장은 하나님께서 아합 왕가에 대한 심판을 집행하시는 장면을 보여줍니다. 엘리사는 선지자의 제자를 길르앗 라못으로 보내 예후에게 기름을 부어 왕으로 세우게 합니다. 이는 단순한 왕위 계승이 아니라, 아합과 이세벨이 저지른 악행에 대한 하나님의 공의로운 심판이 시작되는 순간이었습니다.\n\n예후가 기름 부음을 받는 과정은 매우 은밀하고 급박하게 진행됩니다. 선지자의 제자는 예후를 골방으로 데려가 기름을 붓고는 즉시 도망치듯 떠납니다. 이는 하나님의 심판이 이미 정해진 일이며, 더 이상 지체할 수 없음을 보여줍니다. 예후의 동료 장군들은 처음에는 의아해했지만, 그가 기름 부음 받았다는 소식을 듣자 즉시 그를 왕으로 인정하고 나팔을 불어 선포합니다. 하나님의 때가 이르면 모든 것이 신속하게 진행되는 것입니다.\n\n나봇의 포도원에서 일어난 요람과 예후의 만남은 특별한 의미를 지닙니다. 바로 그 장소는 아합이 나봇을 죽이고 빼앗은 땅이었습니다. "내가 어제 나봇의 피와 그의 아들들의 피를 분명히 보았노라"(왕하 9:26)는 하나님의 말씀대로, 요람은 그의 아버지가 죄를 지은 바로 그 땅에서 심판을 받습니다. 하나님은 불의를 결코 잊지 않으시며, 정확한 장소에서 공의를 실현하십니다.\n\n이세벨의 최후는 더욱 처참합니다. 왕비의 위엄을 유지하려 화장을 하고 머리를 꾸몄지만, 그녀는 창문에서 떨어져 개들에게 뜯겨 먹힙니다. 엘리야를 통해 예언된 대로(왕상 21:23) 정확히 성취된 것입니다. 권력과 교만으로 하나님의 선지자들을 핍박하고 백성을 우상숭배로 이끌었던 이세벨의 삶은 비참한 종말을 맞았습니다.\n\n이 장면들은 하나님의 공의가 때로는 더디 보여도 반드시 이루어진다는 것을 가르쳐 줍니다. 아합 왕가의 악행은 한 세대를 넘어 계속되었지만, 하나님은 적절한 때에 심판의 그릇으로 예후를 준비하셨습니다. 우리는 이를 통해 하나님께서 역사의 주관자이시며, 모든 불의를 기억하고 계신다는 사실을 깨닫게 됩니다.', E'오늘의 핵심\n하나님은 아합 왕가의 악행을 잊지 않으셨고, 예후를 통해 나봇의 억울한 죽음과 선지자들의 피를 갚으셨습니다. 하나님의 공의는 때로 더디 보여도 반드시 실현됩니다.\n\n묵상 질문\n1. 하나님께서 불의를 심판하시는 때를 기다리는 동안, 우리는 어떤 자세를 가져야 할까요?\n2. 나봇의 포도원에서 일어난 심판이 주는 교훈은 무엇일까요?\n3. 권력과 교만이 가져오는 결과를 보며, 내 삶에서 경계해야 할 것은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-23', E'요아스의 치적과 여로보암 2세 (열왕기하 10장)', E'열왕기하 10장', E'예후의 개혁은 철저했지만 불완전했습니다. 하나님께서는 엘리야를 통해 예고하신 대로 아합 왕가에 대한 심판을 예후를 통해 실행하셨습니다. 아합의 아들 칠십 명이 사마리아에 있었는데, 예후는 그들을 돌보는 지도자들에게 도전장을 내밀었습니다. 그러나 두 왕을 쓰러뜨린 예후의 위세 앞에서 그들은 저항할 엄두조차 내지 못했고, 오히려 왕자들을 모두 죽여 그 머리를 예후에게 보냈습니다. 예후는 이를 통해 자신이 단지 개인적 야심으로 움직이는 것이 아니라 하나님의 말씀을 성취하는 도구임을 백성들에게 분명히 했습니다.\n\n더 나아가 예후는 바알 숭배를 뿌리 뽑기 위한 대담한 계략을 펼쳤습니다. 바알을 더욱 열심히 섬기겠다고 선포하여 모든 바알 숭배자들을 한 곳에 모은 후, 그들을 일거에 제거했습니다. 바알의 신당은 헐어서 변소로 만들어 버렸고, 이로써 북이스라엘에서 바알 숭배는 공식적으로 사라졌습니다. 하나님께서도 예후의 이러한 행동을 인정하시어 그의 후손이 4대까지 왕위를 이을 것이라고 약속하셨습니다.\n\n그러나 예후의 개혁에는 치명적인 한계가 있었습니다. 그는 바알은 제거했지만, 벧엘과 단에 있는 금송아지는 그대로 두었습니다. 여로보암이 만든 이 우상들은 정치적 이유로 제거하지 못했던 것입니다. 예후는 "전심으로 이스라엘 하나님 여호와의 율법을 지켜 행하지 아니하였다"(왕하 10:31)고 성경은 평가합니다. 겉으로는 하나님을 위한 열심이었지만, 그의 마음 깊은 곳에는 여전히 정치적 계산이 자리잡고 있었습니다.\n\n예후의 불완전한 개혁은 우리에게 중요한 교훈을 줍니다. 부분적인 순종은 결국 불순종입니다. 눈에 띄는 큰 죄악은 제거하면서도 익숙하고 편리한 작은 타협은 남겨두는 우리의 모습이 예후와 닮지 않았는지 돌아보게 됩니다. 진정한 개혁은 전인격적이고 전면적이어야 합니다. 하나님께서는 우리의 열심보다 온전한 마음을 원하십니다.', E'오늘의 핵심\n예후는 아합 왕가를 심판하고 바알 숭배를 제거했지만, 금송아지 우상은 남겨두는 불완전한 개혁을 했습니다. 하나님은 부분적 순종이 아닌 전심으로 드리는 온전한 헌신을 원하십니다.\n\n묵상 질문\n1. 예후처럼 큰 죄는 끊었지만 작은 타협은 남겨둔 영역이 내 삶에 있을까요?\n2. 하나님을 위한 열심이 때로는 정치적 계산이나 개인적 야심과 섞일 수 있다는 것을 어떻게 분별할 수 있을까요?\n3. 온전한 개혁과 변화를 위해 내가 포기해야 할 ''금송아지''는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-24', E'요아스의 치적과 여로보암 2세 (열왕기하 11장)', E'열왕기하 11장', E'다윗 왕조의 등불이 꺼질 뻔한 위기의 순간이었습니다. 아하시야가 죽자 그의 어머니 아달랴가 왕위를 차지하기 위해 다윗의 모든 후손을 죽이려 했습니다. 북이스라엘 아합 왕가의 딸이었던 그녀는 바알 숭배와 함께 아합 가문의 잔인성도 그대로 물려받았습니다. 손자들까지 모두 죽이는 그녀의 모습은 권력에 대한 맹목적 욕망이 어떻게 인간성을 파괴하는지를 보여줍니다.\n\n그러나 하나님께서는 다윗에게 "항상 등불을 주겠다"고 하신 약속을 잊지 않으셨습니다. 요람 왕의 딸 여호세바가 용기를 내어 갓난아기 요아스를 죽음의 위기에서 구해냅니다. 그녀는 아달랴의 딸이면서도 제사장 여호야다의 아내로서 하나님의 뜻을 따르는 삶을 선택했습니다. 한 여인의 결단이 하나님의 구원 역사를 이어가는 통로가 되었습니다.\n\n6년이라는 긴 시간 동안 어린 요아스는 성전에 숨어 지냈습니다. 아달랴가 나라를 다스리며 바알 숭배를 퍼뜨리는 동안, 성전은 다윗 왕조의 씨앗을 품고 있는 은신처였습니다. 제사장 여호야다는 때를 기다리며 신중하게 준비했습니다. 마침내 7년째 되는 해, 그는 군대 지휘관들과 은밀히 언약을 맺고 요아스를 왕으로 세우는 일을 진행합니다.\n\n왕의 대관식은 철저히 하나님의 율법을 따라 거행되었습니다. 여호야다는 요아스에게 왕관과 함께 율법책을 주었는데, 이는 왕이 하나님의 말씀을 따라 다스려야 함을 보여주는 상징적 행위였습니다. 백성들이 "왕의 만세"를 외치며 기뻐할 때, 아달랴는 "반역이로다"라고 외쳤지만 진정한 반역자는 그녀 자신이었습니다.\n\n여호야다는 왕과 백성이 여호와와 언약을 맺도록 인도했습니다. 이는 단순한 정권 교체가 아니라 신앙의 회복이었습니다. 백성들은 바알 신당을 허물고 우상을 깨뜨렸으며, 그 결과 온 성이 평온을 되찾았습니다. 7세의 어린 왕 요아스의 즉위는 하나님께서 가장 연약한 자를 통해서도 당신의 뜻을 이루신다는 것을 보여줍니다.', E'오늘의 핵심\n하나님께서는 아달랴의 학살 속에서도 여호세바의 용기와 여호야다의 신실함을 통해 다윗 왕조를 보존하시고, 7세 어린 왕을 통해 언약 백성을 회복시키셨습니다.\n\n묵상 질문\n1. 절망적 상황에서도 하나님의 약속을 믿고 행동할 용기가 내게 있습니까?\n2. 여호세바처럼 위험을 무릅쓰고도 지켜야 할 하나님의 일은 무엇일까요?\n3. 내 삶과 공동체에 무너뜨려야 할 ''바알의 신당''은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-02-25', E'요아스의 치적과 여로보암 2세 (열왕기하 12장)', E'열왕기하 12장', E'남유다에서는 아달랴의 폭정이 끝나고 다윗 왕가의 정통 후손 요아스가 일곱 살에 왕위에 올랐습니다. 제사장 여호야다의 보호와 교육 아래 성장한 요아스는 여호와 보시기에 정직하게 행하며 성전 수리라는 중요한 과업에 착수합니다. 오랜 세월 방치되어 무너져가던 성전을 보수하는 일은 단순한 건물 수리 이상의 의미를 담고 있었습니다. 그것은 아달랴 시대에 무너진 여호와 신앙을 회복하는 상징적인 사업이었습니다.\n\n그런데 왕이 성전 수리를 명령한 지 23년이 지나도록 제사장들은 이를 실행하지 않았습니다. 제사장들이 받은 헌금을 성전 수리에 사용하지 않고 다른 용도로 전용했던 것입니다. 요아스는 새로운 시스템을 도입합니다. 성전 입구에 헌금함을 설치하고, 모인 헌금을 투명하게 관리하여 오직 성전 수리에만 사용하도록 했습니다. 이렇게 해서 드디어 성전 보수 공사가 시작되었고, "그들이 성실히 일을 하였음이라"(왕하 12:15)는 기록처럼 신실한 일꾼들의 손을 통해 성전이 회복되어 갔습니다.\n\n그러나 이 장의 후반부는 충격적인 반전을 보여줍니다. 아람 왕 하사엘이 침공해 오자 요아스는 성전의 모든 성물과 보물을 털어 그에게 바치고 평화를 샀습니다. 자신이 그토록 정성을 들여 수리한 성전의 보물을 이방 왕에게 넘겨준 것입니다. 더욱 비극적인 것은 요아스가 신하들의 반역으로 암살당했다는 사실입니다. 성전을 수리하던 개혁 군주가 왜 이런 비참한 최후를 맞았을까요? \n\n역대기는 우리에게 중요한 단서를 제공합니다. 여호야다가 죽은 후 요아스는 우상 숭배에 빠졌고, 자신을 책망하러 온 여호야다의 아들 스가랴를 성전 뜰에서 돌로 쳐 죽였습니다. 그의 신앙은 여호야다라는 울타리 안에서만 유지되던 의존적 신앙이었던 것입니다. 좋은 환경과 훌륭한 지도자가 있을 때는 바르게 살 수 있었지만, 그것이 사라지자 신앙도 함께 무너졌습니다. 성전은 수리했지만 자신의 마음 성전은 끝내 견고하게 세우지 못한 요아스의 삶이 우리에게 던지는 질문은 무겁습니다.', E'오늘의 핵심\n요아스는 여호야다의 지도 아래 성전을 수리하는 개혁을 단행했지만, 그의 신앙은 스승에게 의존한 것이었기에 여호야다 사후 무너지고 말았습니다.\n\n묵상 질문\n1. 나의 신앙은 환경이나 사람에게 의존하고 있지는 않은가요?\n2. 하나님의 성전을 수리하듯 내 마음의 성전도 돌보고 있나요?\n3. 신앙의 스승이 곁에 없을 때도 나는 하나님 앞에 바로 설 수 있을까요?');
